      translatedAudit.summary?.source_pack_rows_checked === sourcePack.cross_fixture_summary?.total_elements,
    `broad fixtures=${broadFixtureMatches.join(", ") || "none"}; gaps=${sourcePackGaps.join(", ") || "none"}`
