async function validateDesignerCandidateDashboard(dashboard, dashboardPath) {
  const failures = [];
  const checks = {};
  const check = (name, passed, detail) => {
    checks[name] = { passed: Boolean(passed), detail };
    if (!passed) {
      failures.push(`${name}: ${detail}`);
    }
  };

  const manifest = await readJson("artifacts/artifact-manifest.json");
  const contradictoryGuard = await readJson(manifest.contradictory_claim_guard_result_path || DEFAULT_CONTRADICTORY_CLAIM_GUARD_OUTPUT);
  const downstreamGate = await readJson(manifest.downstream_source_span_adoption_gate_result_path || DEFAULT_DOWNSTREAM_SOURCE_SPAN_ADOPTION_GATE_OUTPUT);
  const providerEnvelope = await readJson(manifest.provider_envelope_readiness_no_call_result_path || DEFAULT_PROVIDER_ENVELOPE_READINESS_NO_CALL_OUTPUT);
  const sourcePack = await readJson(manifest.source_span_review_pack_path || "artifacts/source-span-routing-review-pack.json");
  const credentialFindings = collectCredentialMaterial(dashboard);
  const contentCandidates = Array.isArray(dashboard.content_candidates) ? dashboard.content_candidates : [];
  const channelStrategyProposals = Array.isArray(dashboard.channel_strategy_proposals) ? dashboard.channel_strategy_proposals : [];
  const draftSpineBeats = Array.isArray(dashboard.draft_spine?.beats) ? dashboard.draft_spine.beats : [];
  const reviewRisks = Array.isArray(dashboard.review_risks) ? dashboard.review_risks : [];
  const heldDecisions = Array.isArray(dashboard.human_owned_decisions_held) ? dashboard.human_owned_decisions_held : [];
  const counts = dashboard.counts || {};

  check(
    "identity",
    dashboard?.artifact_id === "fff-designer-candidate-dashboard-001" &&
      dashboard?.schemaVersion === DESIGNER_CANDIDATE_DASHBOARD_SCHEMA_VERSION &&
      dashboard?.review_ui === "public/review/index.html",
    `artifact=${dashboard?.artifact_id}; schema=${dashboard?.schemaVersion}; ui=${dashboard?.review_ui}`
  );
  check(
    "local_only_boundaries",
    dashboard?.local_only === true &&
      dashboard?.external_call === false &&
      dashboard?.provider_configured === false &&
      dashboard?.credentials_touched === false &&
      dashboard?.public_upload === false &&
      dashboard?.ai_video_generation === false &&
      dashboard?.final_canon_decision === false &&
      credentialFindings.length === 0,
    `local=${dashboard?.local_only}; external=${dashboard?.external_call}; provider=${dashboard?.provider_configured}; credentials=${dashboard?.credentials_touched}; findings=${credentialFindings.join(", ") || "none"}`
  );
  check(
    "review_surface_counts",
    contentCandidates.length >= 3 &&
      channelStrategyProposals.length >= 3 &&
      draftSpineBeats.length >= 5 &&
      reviewRisks.length >= 4 &&
      heldDecisions.length >= 3,
    `content=${contentCandidates.length}; channels=${channelStrategyProposals.length}; beats=${draftSpineBeats.length}; risks=${reviewRisks.length}; held=${heldDecisions.length}`
  );
  check(
    "reported_counts_match",
    counts.content_candidates === contentCandidates.length &&
      counts.channel_strategy_proposals === channelStrategyProposals.length &&
      counts.draft_spine_beats === draftSpineBeats.length &&
      counts.unresolved_risks === reviewRisks.length &&
      counts.human_owned_decisions_held === heldDecisions.length,
    `counts=${JSON.stringify(counts)}`
  );
  check(
    "required_card_fields_visible",
    contentCandidates.every((candidate) =>
      candidate.title_or_hook &&
      candidate.format_fit &&
      candidate.premise_audience_promise &&
      candidate.draft_readiness &&
      candidate.visual_or_thumbnail_direction &&
      candidate.subtitle_or_narration_promise &&
      Array.isArray(candidate.unresolved_risks) &&
      candidate.recommended_next_review_decision
    ) &&
      channelStrategyProposals.every((proposal) =>
        proposal.channel_archetype &&
        proposal.target_audience &&
        Array.isArray(proposal.content_pillars) &&
        proposal.series_angle &&
        proposal.cadence_hypothesis &&
        proposal.material_fit &&
        Array.isArray(proposal.risk_flags) &&
        proposal.review_debt
      ),
    `contentFields=${contentCandidates.length}; channelFields=${channelStrategyProposals.length}`
  );
  check(
    "draft_is_not_final_prose",
    dashboard.draft_spine?.status === "reviewable_not_final_prose" &&
      dashboard.final_canon_decision === false &&
      draftSpineBeats.every((beat) => beat.review_status === "hold"),
    `draftStatus=${dashboard.draft_spine?.status}; finalCanon=${dashboard.final_canon_decision}`
  );
  check(
    "absence_and_unknowns_visible",
    dashboard.absence_policy?.unknown_fields_visible === true &&
      dashboard.absence_policy?.missing_data_label &&
      reviewRisks.some((risk) => String(risk.finding || "").toLowerCase().includes("no render")) &&
      reviewRisks.some((risk) => String(risk.finding || "").toLowerCase().includes("rights")),
    `unknowns=${dashboard.absence_policy?.unknown_fields_visible}; label=${dashboard.absence_policy?.missing_data_label}`
  );
  check(
    "guard_chain_preserved",
    contradictoryGuard?.passed === true &&
      contradictoryGuard.summary?.adopted_or_provisional_conflicting_claims === 0 &&
      downstreamGate?.passed === true &&
      downstreamGate.summary?.adopted_profile_claim_timeline_candidates === 0 &&
      providerEnvelope?.passed === true &&
      providerEnvelope.provider_metadata?.externalCallAttempted === false &&
      sourcePack?.passed === true,
    `conflictAdopted=${contradictoryGuard.summary?.adopted_or_provisional_conflicting_claims}; downstreamAdopted=${downstreamGate.summary?.adopted_profile_claim_timeline_candidates}; external=${providerEnvelope.provider_metadata?.externalCallAttempted}; pack=${sourcePack?.passed}`
  );

  return {
    schemaVersion: DESIGNER_CANDIDATE_DASHBOARD_SCHEMA_VERSION,
    artifact_id: "fff-designer-candidate-dashboard-001",
    title: "Fast Fiction Factory Designer Candidate Dashboard",
    generatedAt: new Date().toISOString(),
    review_status: "ready_for_local_readback",
    review_input_mode: "freeform",
    review_ui: dashboard.review_ui || "public/review/index.html",
    access_route: dashboard.access_route || "public/review/index.html?mode=designer",
    input_result_path: toRepoPath(dashboardPath),
    local_only: dashboard.local_only === true,
    external_call: false,
    provider_configured: false,
    credentials_touched: false,
    public_upload: false,
    ai_video_generation: false,
    final_canon_decision: false,
    content_candidates: contentCandidates,
    channel_strategy_proposals: channelStrategyProposals,
    draft_spine: dashboard.draft_spine || {},
    review_risks: reviewRisks,
    human_owned_decisions_held: heldDecisions,
    absence_policy: dashboard.absence_policy || {},
    counts: {
      content_candidates: contentCandidates.length,
      channel_strategy_proposals: channelStrategyProposals.length,
      draft_spine_beats: draftSpineBeats.length,
      unresolved_risks: reviewRisks.length,
      human_owned_decisions_held: heldDecisions.length
    },
    preserved_readbacks: {
      contradictory_claim_guard: contradictoryGuard?.artifact_id,
      downstream_source_span_adoption_gate: downstreamGate?.artifact_id,
      provider_envelope_readiness_no_call: providerEnvelope?.artifact_id,
      source_span_review_pack: sourcePack?.artifact_id
    },
    summary: {
      designer_dashboard_visible: checks.identity?.passed === true,
      content_candidate_cards: contentCandidates.length,
      channel_strategy_cards: channelStrategyProposals.length,
      draft_spine_beats: draftSpineBeats.length,
      unresolved_risks: reviewRisks.length,
      human_owned_decisions_held: heldDecisions.length,
      local_only: true,
      external_call_attempted: false,
      provider_configured: false,
      credentials_touched: false,
      public_upload: false,
      ai_video_generation: false,
      final_canon_decision: false,
      guard_chain_preserved: checks.guard_chain_preserved?.passed === true,
      failures: failures.length
    },
    validation_notes: [
      "Designer Dashboard is a local planning and readback surface only.",
      "Content cards, channel proposals, and draft beats remain review-held.",
      "Unknown or human-owned story truth remains visible instead of being invented.",
      "No provider, credential, public upload, AI video generation, production render, or final canon decision is added."
    ],
    dashboard_checks: checks,
    failures,
    passed: failures.length === 0
  };
}

async function readAdapterPayloads() {
  const payloads = [];
  for (const filePath of ["artifacts/local-extraction-adapter-output.json"]) {
    const payload = await readJson(filePath);
    payload.__path = toRepoPath(filePath);
    payloads.push(payload);
  }

  const outputDir = "artifacts/extraction-adapter-outputs";
  const entries = await readdir(outputDir, { withFileTypes: true });
  for (const entry of entries.filter((item) => item.isFile() && item.name.endsWith(".json")).sort((a, b) => a.name.localeCompare(b.name))) {
    const filePath = toRepoPath(path.join(outputDir, entry.name));
    const payload = await readJson(filePath);
    payload.__path = filePath;
    payloads.push(payload);
  }
  return payloads;
}

function flattenSourcePackElements(sourcePack) {
  if (!Array.isArray(sourcePack?.fixtures)) {
    return [];
  }
  return sourcePack.fixtures.flatMap((fixture) => Array.isArray(fixture.elements) ? fixture.elements : []);
}

function claimHasValidSourceRefs(claim, contractSourceRefs) {
  const sourceIds = new Set(
    Array.isArray(contractSourceRefs)
      ? contractSourceRefs.map((sourceRef) => sourceRef?.id).filter(Boolean)
      : []
  );
  return Array.isArray(claim?.sourceRefs) &&
    claim.sourceRefs.length > 0 &&
    claim.sourceRefs.every((sourceRef) => {
      const sourceRefId = typeof sourceRef === "string" ? sourceRef : sourceRef?.id;
      return typeof sourceRefId === "string" && sourceIds.has(sourceRefId);
    });
}

function hasValidSourceSpan(element) {
  const span = element?.sourceSpan;
  return Boolean(span) &&
    typeof span === "object" &&
    typeof span.text === "string" &&
    span.text.trim().length > 0 &&
    Number.isInteger(span.start) &&
    Number.isInteger(span.end) &&
    span.start >= 0 &&
    span.end > span.start;
}

function isUnsafeDownstreamRoute(packElement, adapterElement) {
  const packRoutes = Array.isArray(packElement?.routing_targets) ? packElement.routing_targets : [];
  const adapterDestinations = Array.isArray(adapterElement?.targetDestinations) ? adapterElement.targetDestinations : [];
  if (packElement?.element_type === "visual_asset" && packRoutes.includes("Claim")) {
    return true;
  }
  if (adapterElement?.elementType === "visual_asset" && adapterDestinations.includes("claim")) {
    return true;
  }
  if (packElement?.element_type === "source_reference" && packRoutes.some((target) => ["Claim", "Profile", "Timeline"].includes(target))) {
    return true;
  }
  if (adapterElement?.elementType === "source_reference" && adapterDestinations.some((target) => ["claim", "profile", "timeline"].includes(target))) {
    return true;
  }
  if (packElement?.element_type === "unresolved_decision" && !packRoutes.includes("Human Review")) {
    return true;
  }
  if (adapterElement?.elementType === "unresolved_decision" && !adapterDestinations.includes("unresolved_decision")) {
    return true;
  }
  return false;
}

function arrayLength(value) {
  return Array.isArray(value) ? value.length : 0;
}

function arrayIncludesIgnoreCase(value, expected) {
  if (!Array.isArray(value)) {
    return false;
  }
  const target = String(expected).toLowerCase();
  return value.some((item) => String(item).toLowerCase() === target);
}

function arrayIncludesSubstring(value, expected) {
  if (!Array.isArray(value)) {
    return false;
  }
  const target = String(expected).toLowerCase();
  return value.some((item) => String(item).toLowerCase().includes(target));
}

function arrayEqualsIgnoreCase(value, expected) {
  if (!Array.isArray(value) || value.length !== expected.length) {
    return false;
  }
  return value.every((item, index) => String(item).toLowerCase() === String(expected[index]).toLowerCase());
}

function hasHumanOwnedDependency(decision) {
  const searchable = [
    decision.extracted_value,
    decision.hold_reason,
    decision.guard_condition,
    ...(Array.isArray(decision.unresolvedDependencies) ? decision.unresolvedDependencies : [])
  ].filter(Boolean).join(" ").toLowerCase();
  return HUMAN_OWNED_DECISIONS.some((item) => searchable.includes(item.toLowerCase()));
}

function toRepoPath(filePath) {
  const relativePath = path.isAbsolute(filePath) ? path.relative(process.cwd(), filePath) : filePath;
  return relativePath.replace(/\\/g, "/");
}

async function fileSizeOrZero(filePath) {
  try {
    const info = await stat(filePath);
    return info.isFile() ? info.size : 0;
  } catch {
    return 0;
  }
}

async function readFileSnapshot(filePath) {
  try {
    const buffer = await readFile(filePath);
    return {
      path: toRepoPath(filePath),
      exists: true,
      buffer,
      text: buffer.toString("utf8"),
      byteSize: buffer.byteLength,
      sha256: createHash("sha256").update(buffer).digest("hex"),
      error: null
    };
  } catch (error) {
    return {
      path: toRepoPath(filePath),
      exists: false,
      buffer: null,
      text: "",
      byteSize: 0,
      sha256: null,
      error: error.message
    };
  }
}

function parseJsonSnapshot(snapshot) {
  if (!snapshot?.exists) {
    return { value: null, error: snapshot?.error || "file missing" };
  }
  try {
    return { value: JSON.parse(snapshot.text), error: null };
  } catch (error) {
    return { value: null, error: `Invalid JSON in ${snapshot.path}: ${error.message}` };
  }
}

async function readJsonFileSnapshot(filePath) {
  const snapshot = await readFileSnapshot(filePath);
  const parsed = parseJsonSnapshot(snapshot);
  return {
    ...snapshot,
    value: parsed.value,
    error: parsed.error
  };
}

function parseCsvSnapshot(snapshot) {
  if (!snapshot?.exists) {
    return { headers: [], records: [], error: snapshot?.error || "file missing" };
  }
  try {
    const parsed = parseCsvText(snapshot.text);
    return { ...parsed, error: null };
  } catch (error) {
    return { headers: [], records: [], error: `Invalid CSV in ${snapshot.path}: ${error.message}` };
  }
}

function parseCsvText(text) {
  const rows = [];
  let row = [];
  let field = "";
  let inQuotes = false;

  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    if (inQuotes) {
      if (char === '"') {
        if (text[index + 1] === '"') {
          field += '"';
          index += 1;
        } else {
          inQuotes = false;
        }
      } else {
        field += char;
      }
      continue;
    }

    if (char === '"') {
      if (field.length > 0) {
        throw new Error("unexpected quote inside an unquoted field");
      }
      inQuotes = true;
    } else if (char === ",") {
      row.push(field);
      field = "";
    } else if (char === "\n" || char === "\r") {
      if (char === "\r" && text[index + 1] === "\n") {
        index += 1;
      }
      row.push(field);
      if (row.some((value) => value.length > 0)) {
        rows.push(row);
      }
      row = [];
      field = "";
    } else {
      field += char;
    }
  }

  if (inQuotes) {
    throw new Error("unterminated quoted field");
  }
  row.push(field);
  if (row.some((value) => value.length > 0)) {
    rows.push(row);
  }
  if (rows.length === 0) {
    throw new Error("CSV is empty");
  }

  const headers = rows[0].map((value, index) => index === 0 ? value.replace(/^\uFEFF/, "") : value);
  if (new Set(headers).size !== headers.length || headers.some((header) => header.length === 0)) {
    throw new Error("CSV headers must be unique and non-empty");
  }
  const records = rows.slice(1).map((values, index) => {
    if (values.length !== headers.length) {
      throw new Error(`row ${index + 2} has ${values.length} columns; expected ${headers.length}`);
    }
    return Object.fromEntries(headers.map((header, columnIndex) => [header, values[columnIndex]]));
  });
  return { headers, records };
}

function parseEditorialTimeSeconds(value) {
  if (typeof value !== "string" && typeof value !== "number") {
    return null;
  }
  if (typeof value === "number") {
    return Number.isFinite(value) && value >= 0 ? value : null;
  }
  const normalized = value.trim();
  if (!normalized) {
    return null;
  }
  const parts = normalized.split(":");
  if (parts.length !== 2 && parts.length !== 3) {
    return null;
  }
  const numbers = parts.map(Number);
  if (numbers.some((number) => !Number.isFinite(number) || number < 0)) {
    return null;
  }
  const seconds = numbers[numbers.length - 1];
  const minutes = numbers[numbers.length - 2];
  const hours = numbers.length === 3 ? numbers[0] : 0;
  if (seconds >= 60 || (numbers.length === 3 && minutes >= 60)) {
    return null;
  }
  return (hours * 3600) + (minutes * 60) + seconds;
}

function validateEditorialTimedSequence(items, idKey, beatById) {
  const errors = [];
  let previousEnd = -1;
  for (const [index, item] of items.entries()) {
    const id = String(item?.[idKey] || `<row ${index + 1}>`);
    const beatId = String(item?.beat_id || "");
    const beat = beatById.get(beatId);
    const start = parseEditorialTimeSeconds(item?.start_time);
    const end = parseEditorialTimeSeconds(item?.end_time);
    if (!beat) {
      errors.push(`${id}: invalid beat_id ${beatId || "<empty>"}`);
      continue;
    }
    if (start === null || end === null || start >= end) {
      errors.push(`${id}: invalid range ${item?.start_time}-${item?.end_time}`);
      continue;
    }
    if (start < beat.start_seconds || end > beat.end_seconds) {
      errors.push(`${id}: range ${start}-${end} is outside ${beatId} ${beat.start_seconds}-${beat.end_seconds}`);
    }
    if (start < previousEnd) {
      errors.push(`${id}: start ${start} overlaps or precedes prior end ${previousEnd}`);
    }
    previousEnd = end;
  }
  return { errors };
}

function countItemsByKey(items, key) {
  const counts = new Map();
  for (const item of items) {
    const value = String(item?.[key] || "");
    counts.set(value, (counts.get(value) || 0) + 1);
  }
  return counts;
}

function hasNonEmptyText(value) {
  return typeof value === "string" && value.trim().length > 0;
}

function arrayEqualsExact(value, expected) {
  return Array.isArray(value) &&
    value.length === expected.length &&
    value.every((item, index) => item === expected[index]);
}

function csvRecordsMatchObjects(records, objects, headers) {
  if (!Array.isArray(records) || !Array.isArray(objects) || records.length !== objects.length) {
    return false;
  }
  return records.every((record, index) => headers.every((header) =>
    String(record?.[header] ?? "") === String(objects[index]?.[header] ?? "")
  ));
}

function editorialInventoryPath(entry) {
  const raw = typeof entry === "string"
    ? entry
    : entry?.relative_path ?? entry?.path ?? entry?.file_path ?? entry?.filename ?? entry?.name;
  if (!raw) {
    return "";
  }
  const normalized = toRepoPath(String(raw)).replace(/^\.\//, "");
  const packagePrefix = `${EDITORIAL_HANDOFF_PACKAGE_ROOT}/`;
  return normalized.startsWith(packagePrefix) ? normalized.slice(packagePrefix.length) : normalized;
}

function htmlAttributePattern(attributeName, expectedValue) {
  const name = escapeRegExp(attributeName);
  if (expectedValue === undefined) {
    return new RegExp(`\\b${name}(?:\\s*=\\s*(?:"[^"]*"|'[^']*'|[^\\s>]+))?`, "i");
  }
  const value = escapeRegExp(expectedValue);
  return new RegExp(`\\b${name}\\s*=\\s*(?:"${value}"|'${value}')`, "i");
}

function hasHtmlAttribute(html, attributeName, expectedValue) {
  return htmlAttributePattern(attributeName, expectedValue).test(html);
}

function findHtmlAttributeIndex(html, attributeName, expectedValue) {
  return html.search(htmlAttributePattern(attributeName, expectedValue));
}

async function buildEditorialHandoffPackageManifest() {
  const files = [];
  for (const relativePath of EDITORIAL_HANDOFF_PACKAGE_FILES) {
    const filePath = `${EDITORIAL_HANDOFF_PACKAGE_ROOT}/${relativePath}`;
    const buffer = await readFile(filePath);
    files.push({
      relative_path: relativePath,
      byte_size: buffer.byteLength,
      sha256: createHash("sha256").update(buffer).digest("hex")
    });
  }
  return {
    schemaVersion: EDITORIAL_HANDOFF_PACKAGE_MANIFEST_SCHEMA_VERSION,
    artifact_id: "fff-bridge-editorial-handoff-pack-001",
    generatedAt: new Date().toISOString(),
    package_root: EDITORIAL_HANDOFF_PACKAGE_ROOT,
    files,
    passed: true
  };
}

async function buildEditorialRevisionPackageManifest() {
  const files = [];
  for (const relativePath of EDITORIAL_REVISION_PACKAGE_FILES) {
    const filePath = EDITORIAL_REVISION_PACKAGE_ROOT + "/" + relativePath;
    const buffer = await readFile(filePath);
    files.push({
      relative_path: relativePath,
      byte_size: buffer.byteLength,
      sha256: createHash("sha256").update(buffer).digest("hex")
    });
  }
  return {
    schemaVersion: EDITORIAL_REVISION_PACKAGE_MANIFEST_SCHEMA_VERSION,
    artifact_id: EDITORIAL_REVISION_ARTIFACT_ID,
    generatedAt: new Date().toISOString(),
    package_root: EDITORIAL_REVISION_PACKAGE_ROOT,
    source: {
      artifact_id: EDITORIAL_REVISION_SOURCE_ARTIFACT_ID,
      editorial_handoff_sha256: EDITORIAL_REVISION_SOURCE_HANDOFF_SHA256,
      package_manifest_sha256: EDITORIAL_REVISION_SOURCE_MANIFEST_SHA256
    },
    files,
    passed: files.length === EDITORIAL_REVISION_PACKAGE_FILES.length
  };
}

async function readEditorialRevisionSmokeSeed(inputPath, targetPath) {
  if (path.resolve(inputPath) !== path.resolve(targetPath)) {
    return readJson(inputPath);
  }
  return {
    schemaVersion: EDITORIAL_REVISION_ROUNDTRIP_SCHEMA_VERSION,
    artifact_id: EDITORIAL_REVISION_ARTIFACT_ID,
    revision_route: "public/review/index.html?mode=revision",
    handoff_route: "public/review/index.html?mode=handoff",
    bridge_route: "public/review/index.html?mode=bridge",
    brief_route: "public/review/index.html?mode=brief",
    source: {
      artifact_id: EDITORIAL_REVISION_SOURCE_ARTIFACT_ID,
      editorial_handoff_sha256: EDITORIAL_REVISION_SOURCE_HANDOFF_SHA256,
      package_manifest_sha256: EDITORIAL_REVISION_SOURCE_MANIFEST_SHA256
    },
    boundaries: {
      local_only: true,
      external_call: false,
      provider_configured: false,
      credentials_touched: false,
      public_upload: false,
      ai_video_generation: false,
      production_render: false,
      database_persistence: false,
      final_canon_decision: false,
      rights_cleared_claim: false
    },
    failures: [],
    passed: true
  };
}

async function buildEditorialDerivativePackageArtifacts() {
  const errors = [];
  const [sourceSnapshot, patchSnapshot, requestSnapshot, decisionSnapshot] = await Promise.all([
    readJsonFileSnapshot(`${EDITORIAL_HANDOFF_PACKAGE_ROOT}/editorial-handoff.json`),
    readJsonFileSnapshot(EDITORIAL_DERIVATIVE_PATCH_PATH),
    readJsonFileSnapshot(`${EDITORIAL_REVISION_PACKAGE_ROOT}/revision-request.example.json`),
    readJsonFileSnapshot(`${EDITORIAL_REVISION_PACKAGE_ROOT}/revision-decision.example.json`)
  ]);
  const sourceHandoff = sourceSnapshot.value || {};
  const revisionPatch = patchSnapshot.value || {};
  const request = requestSnapshot.value || {};
  const decision = decisionSnapshot.value || {};
  const sourceFingerprint = {
    artifact_id: EDITORIAL_REVISION_SOURCE_ARTIFACT_ID,
    editorial_handoff_sha256: EDITORIAL_REVISION_SOURCE_HANDOFF_SHA256,
    package_manifest_sha256: EDITORIAL_REVISION_SOURCE_MANIFEST_SHA256
  };

  for (const snapshot of [sourceSnapshot, patchSnapshot, requestSnapshot, decisionSnapshot]) {
    if (snapshot.error) {
      errors.push(snapshot.error);
    }
  }
  const requestValidation = validateEditorialRevisionRequestPayload(
    request,
    sourceHandoff,
    sourceFingerprint
  );
  const decisionValidation = validateEditorialRevisionDecisionPayload(
    decision,
    request,
    requestValidation,
    sourceFingerprint
  );
  const patchValidation = validateEditorialRevisionPatchPayload(
    revisionPatch,
    request,
    decision,
    requestValidation,
    sourceFingerprint
  );
  const derivativePatchValidation = validateEditorialDerivativePatchInput(
    revisionPatch,
    patchSnapshot.sha256,
    sourceHandoff,
    sourceFingerprint
  );
  if (!requestValidation.valid) {
    errors.push(...requestValidation.errors.map((error) => `request: ${error}`));
  }
  if (!decisionValidation.valid) {
    errors.push(...decisionValidation.errors.map((error) => `decision: ${error}`));
  }
  if (!patchValidation.valid) {
    errors.push(...patchValidation.errors.map((error) => `patch: ${error}`));
  }
  if (!derivativePatchValidation.valid) {
    errors.push(...derivativePatchValidation.errors.map((error) => `derivative patch: ${error}`));
  }
  if (errors.length > 0) {
    return { valid: false, errors, files: {} };
  }

  const derivativeBuild = buildEditorialDerivativeModel(
    sourceHandoff,
    revisionPatch,
    sourceFingerprint,
    patchSnapshot.sha256
  );
  if (!derivativeBuild.valid) {
    return { valid: false, errors: derivativeBuild.errors, files: {} };
  }
  const derived = derivativeBuild.derived;
  const files = {
    "narration-script.derived.md": editorialDerivativeUtf8(
      renderEditorialDerivativeNarration(derived)
    ),
    "subtitle-cues.derived.csv": editorialDerivativeUtf8(
      renderEditorialDerivativeCsv(derived.subtitle_cues, editorialDerivativeSubtitleHeaders())
    ),
    "shot-list.derived.csv": editorialDerivativeUtf8(
      renderEditorialDerivativeCsv(derived.shot_cues, editorialDerivativeShotHeaders())
    ),
    "editorial-handoff.derived.json": editorialDerivativeJsonBuffer(derived),
    "applied-revision-patch.json": patchSnapshot.buffer
  };
  const coreFingerprint = editorialDerivativeCoreFingerprint(files);
  const provenance = buildEditorialDerivativeProvenance(
    derived,
    sourceHandoff,
    revisionPatch,
    patchSnapshot.sha256,
    files,
    coreFingerprint
  );
  files["derivative-provenance.json"] = editorialDerivativeJsonBuffer(provenance);
  files["README_DERIVATIVE.md"] = editorialDerivativeUtf8(
    renderEditorialDerivativeReadme(derived, provenance)
  );
  const manifest = buildEditorialDerivativePackageManifest(
    derived,
    revisionPatch,
    patchSnapshot.sha256,
    files,
    coreFingerprint
  );
  files["derivative-package-manifest.json"] = editorialDerivativeJsonBuffer(manifest);
  const candidateValidation = validateEditorialDerivativePackageCandidate(files, {
    source_handoff: sourceHandoff,
    revision_patch: revisionPatch,
    patch_sha256: patchSnapshot.sha256,
    source_fingerprint: sourceFingerprint
  });
  if (!candidateValidation.valid) {
    return {
      valid: false,
      errors: candidateValidation.errors.map((error) => `generated package: ${error}`),
      files
    };
  }
  return {
    valid: true,
    errors: [],
    files,
    derived,
    provenance,
    manifest,
    core_fingerprint_sha256: coreFingerprint
  };
}

function buildEditorialDerivativeModel(sourceHandoff, revisionPatch, sourceFingerprint, patchSha256) {
  const errors = [];
  const derived = {
    schemaVersion: EDITORIAL_DERIVATIVE_PREVIEW_SCHEMA_VERSION,
    artifact_id: EDITORIAL_DERIVATIVE_ARTIFACT_ID,
    title: "Fast Fiction Factory Editorial Derivative Preview",
    generatedAt: revisionPatch?.created_at || null,
    status: "derived_revision_preview",
    derived_status: "derived_revision_preview",
    canonical: false,
    source_apply_status: "not_applied",
    derived_apply_status: "applied_to_derived_copy",
    application_scope: "derived_copy_only",
    rollback_action: "discard_derived_package",
    review_route: "public/review/index.html?mode=derivative",
    source: cloneJsonValue(sourceFingerprint),
    patch: {
      patch_id: revisionPatch?.patch_id || null,
      path: EDITORIAL_DERIVATIVE_PATCH_PATH,
      sha256: patchSha256
    },
    selected_candidate_id: sourceHandoff?.selected_candidate_id || null,
    selected_channel_route_id: sourceHandoff?.selected_channel_route_id || null,
    total_duration_seconds: sourceHandoff?.total_duration_seconds ?? null,
    source_artifact_ids: cloneJsonValue(sourceHandoff?.source_artifact_ids || []),
    beats: cloneJsonValue(sourceHandoff?.beats || []),
    narration_segments: cloneJsonValue(sourceHandoff?.narration_segments || []),
    subtitle_cues: cloneJsonValue(sourceHandoff?.subtitle_cues || []),
    shot_cues: cloneJsonValue(sourceHandoff?.shot_cues || []),
    thumbnail_directions: cloneJsonValue(sourceHandoff?.thumbnail_directions || []),
    sound_music_mood_brief: cloneJsonValue(sourceHandoff?.sound_music_mood_brief || {}),
    truth_guards: cloneJsonValue(sourceHandoff?.truth_guards || []),
    rights_guards: cloneJsonValue(sourceHandoff?.rights_guards || []),
    applied_changes: [],
    file_inventory: EDITORIAL_DERIVATIVE_REQUIRED_FILES.map((relativePath) => ({
      relative_path: relativePath,
      required: true
    })),
    boundaries: editorialDerivativeClosedBoundaries()
  };
  const changes = Array.isArray(revisionPatch?.accepted_changes)
    ? revisionPatch.accepted_changes
    : [];
  for (const change of changes) {
    const target = resolveEditorialDerivativeTarget(derived, change);
    if (!target) {
      errors.push(`${change?.change_id || "<missing change>"}: target not found`);
      continue;
    }
    if (!jsonValuesEqual(target.item?.[change.target_field], change.before)) {
      errors.push(`${change.change_id}: before value does not match source-derived copy`);
      continue;
    }
    target.item[change.target_field] = cloneJsonValue(change.proposed_value);
    if (change.target_type === "narration_segment" && change.target_field === "text") {
      target.item.character_count_estimate = Array.from(String(change.proposed_value)).length;
    }
    derived.applied_changes.push({
      change_id: change.change_id,
      beat_id: change.beat_id,
      target_type: change.target_type,
      target_id: change.target_id,
      target_field: change.target_field,
      change_type: change.change_type,
      guard_class: change.guard_class,
      before: cloneJsonValue(change.before),
      after: cloneJsonValue(change.proposed_value)
    });
  }
  const audit = auditEditorialDerivativeModel(sourceHandoff, derived, revisionPatch);
  errors.push(...audit.errors);
  return { valid: errors.length === 0, errors, derived, audit };
}

function resolveEditorialDerivativeTarget(derived, change) {
  const collectionByType = {
    narration_segment: ["narration_segments", "segment_id"],
    subtitle_cue: ["subtitle_cues", "cue_id"],
    shot_cue: ["shot_cues", "shot_id"]
  };
  const mapping = collectionByType[change?.target_type];
  if (!mapping) {
    return null;
  }
  const [collectionName, idField] = mapping;
  const collection = Array.isArray(derived?.[collectionName]) ? derived[collectionName] : [];
  const item = collection.find((candidate) => candidate?.[idField] === change?.target_id);
  if (!item || item?.beat_id !== change?.beat_id || !(change?.target_field in item)) {
    return null;
  }
  return { collectionName, idField, item };
}

function validateEditorialDerivativePatchInput(
  revisionPatch,
  patchSha256,
  sourceHandoff,
  sourceFingerprint
) {
  const errors = [];
  const changes = Array.isArray(revisionPatch?.accepted_changes)
    ? revisionPatch.accepted_changes
    : [];
  if (revisionPatch?.schemaVersion !== EDITORIAL_REVISION_PATCH_SCHEMA_VERSION) {
    errors.push("schemaVersion mismatch");
  }
  if (patchSha256 !== EDITORIAL_DERIVATIVE_PATCH_SHA256) {
    errors.push("patch SHA256 mismatch");
  }
  if (!editorialRevisionSourceMatches(revisionPatch?.source, sourceFingerprint)) {
    errors.push("source fingerprint mismatch");
  }
  if (revisionPatch?.apply_status !== "not_applied") {
    errors.push("source apply status must remain not_applied");
  }
  if (!editorialRevisionBoundariesClosed(revisionPatch)) {
    errors.push("patch boundaries are not closed");
  }
  const changeIds = changes.map((change) => String(change?.change_id || ""));
  if (changes.length !== EDITORIAL_DERIVATIVE_EXPECTED_CHANGES.length ||
      new Set(changeIds).size !== changeIds.length ||
      !arrayEqualsExact(changeIds, EDITORIAL_DERIVATIVE_EXPECTED_CHANGE_IDS)) {
    errors.push("patch must contain exactly the three expected safe changes in order");
  }
  for (const expected of EDITORIAL_DERIVATIVE_EXPECTED_CHANGES) {
    const change = changes.find((candidate) => candidate?.change_id === expected.change_id);
    if (!change) {
      errors.push(`${expected.change_id}: missing`);
      continue;
    }
    const tupleFields = [
      "beat_id",
      "target_type",
      "target_id",
      "target_field",
      "change_type"
    ];
    if (!tupleFields.every((field) => change?.[field] === expected[field])) {
      errors.push(`${expected.change_id}: target tuple mismatch`);
    }
    if (change?.guard_class !== "safe_local_edit") {
      errors.push(`${expected.change_id}: guard class must be safe_local_edit`);
    }
    const sourceTarget = resolveEditorialRevisionSourceTarget(sourceHandoff, change);
    if (!sourceTarget) {
      errors.push(`${expected.change_id}: unknown source target`);
    } else if (!jsonValuesEqual(sourceTarget.value, change?.before)) {
      errors.push(`${expected.change_id}: before value mismatch`);
    }
    if (!hasNonEmptyText(change?.proposed_value) || jsonValuesEqual(change?.before, change?.proposed_value)) {
      errors.push(`${expected.change_id}: proposed value must be non-empty and changed`);
    }
  }
  return { valid: errors.length === 0, errors, change_count: changes.length };
}

function auditEditorialDerivativeModel(sourceHandoff, derived, revisionPatch) {
  const errors = [];
  const changes = Array.isArray(revisionPatch?.accepted_changes)
    ? revisionPatch.accepted_changes
    : [];
  const compareCollections = [
    ["beats", "beat_id"],
    ["narration_segments", "segment_id"],
    ["subtitle_cues", "cue_id"],
    ["shot_cues", "shot_id"],
    ["thumbnail_directions", "direction_id"],
    ["truth_guards", "guard_id"],
    ["rights_guards", "guard_id"]
  ];
  const allowedPaths = new Map();
  for (const change of changes) {
    allowedPaths.set(
      `${change.target_type}/${change.target_id}/${change.target_field}`,
      change
    );
  }
  for (const [collectionName, idField] of compareCollections) {
    const sourceItems = Array.isArray(sourceHandoff?.[collectionName])
      ? sourceHandoff[collectionName]
      : [];
    const derivedItems = Array.isArray(derived?.[collectionName])
      ? derived[collectionName]
      : [];
    if (sourceItems.length !== derivedItems.length) {
      errors.push(`${collectionName}: item count changed`);
      continue;
    }
    for (let index = 0; index < sourceItems.length; index += 1) {
      const sourceItem = sourceItems[index];
      const derivedItem = derivedItems[index];
      if (sourceItem?.[idField] !== derivedItem?.[idField]) {
        errors.push(`${collectionName}: ID or order changed at index ${index}`);
        continue;
      }
      const targetType = collectionName === "narration_segments"
        ? "narration_segment"
        : collectionName === "subtitle_cues"
          ? "subtitle_cue"
          : collectionName === "shot_cues"
            ? "shot_cue"
            : null;
      const keys = new Set([...Object.keys(sourceItem || {}), ...Object.keys(derivedItem || {})]);
      for (const key of keys) {
        const pathKey = `${targetType}/${sourceItem?.[idField]}/${key}`;
        const allowed = targetType ? allowedPaths.get(pathKey) : null;
        if (allowed) {
          if (!jsonValuesEqual(sourceItem?.[key], allowed.before) ||
              !jsonValuesEqual(derivedItem?.[key], allowed.proposed_value)) {
            errors.push(`${allowed.change_id}: before or after value mismatch`);
          }
          continue;
        }
        const narrationEstimateAllowed = collectionName === "narration_segments" &&
          sourceItem?.segment_id === "narration-b01" &&
          key === "character_count_estimate";
        if (narrationEstimateAllowed) {
          const expectedEstimate = Array.from(String(derivedItem?.text || "")).length;
          if (sourceItem?.character_count_estimate !== 93 ||
              derivedItem?.character_count_estimate !== expectedEstimate ||
              expectedEstimate !== 94) {
            errors.push("narration-b01 character_count_estimate must recalculate 93 to 94");
          }
          continue;
        }
        if (!jsonValuesEqual(sourceItem?.[key], derivedItem?.[key])) {
          errors.push(`${collectionName}/${sourceItem?.[idField]}/${key}: hidden change`);
        }
      }
    }
  }
  for (const key of ["sound_music_mood_brief", "source_artifact_ids"]) {
    if (!jsonValuesEqual(sourceHandoff?.[key], derived?.[key])) {
      errors.push(`${key}: hidden change`);
    }
  }
  const applied = Array.isArray(derived?.applied_changes) ? derived.applied_changes : [];
  if (applied.length !== 3 || !arrayEqualsExact(
    applied.map((change) => change?.change_id),
    EDITORIAL_DERIVATIVE_EXPECTED_CHANGE_IDS
  )) {
    errors.push("derived applied_changes must be exactly the three expected changes");
  }
  const sourceNarrationTotal = (sourceHandoff?.narration_segments || [])
    .reduce((total, segment) => total + Number(segment?.character_count_estimate || 0), 0);
  const derivedNarrationTotal = (derived?.narration_segments || [])
    .reduce((total, segment) => total + Number(segment?.character_count_estimate || 0), 0);
  if (sourceNarrationTotal !== 777 || derivedNarrationTotal !== 778) {
    errors.push(`narration character totals must be 777 -> 778, got ${sourceNarrationTotal} -> ${derivedNarrationTotal}`);
  }
  return {
    valid: errors.length === 0,
    errors,
    content_delta_count: changes.length,
    narration_character_count_before: sourceNarrationTotal,
    narration_character_count_after: derivedNarrationTotal
  };
}

function editorialDerivativeSubtitleHeaders() {
  return [
    "cue_id",
    "beat_id",
    "start_time",
    "end_time",
    "text_ja",
    "line_break_hint",
    "status",
    "truth_risk_marker"
  ];
}

function editorialDerivativeShotHeaders() {
  return [
    "shot_id",
    "beat_id",
    "start_time",
    "end_time",
    "shot_purpose",
    "visual_direction",
    "asset_class",
    "asset_status",
    "rights_note",
    "truth_boundary_note"
  ];
}

function renderEditorialDerivativeNarration(derived) {
  const lines = [
    "# Editorial Derivative Preview — Narration Script",
    "",
    "DERIVED PREVIEW / NOT CANONICAL",
    "",
    `- artifact_id: ${derived.artifact_id}`,
    `- status: ${derived.status}`,
    `- source_apply_status: ${derived.source_apply_status}`,
    `- derived_apply_status: ${derived.derived_apply_status}`,
    `- application_scope: ${derived.application_scope}`,
    `- rollback_action: ${derived.rollback_action}`,
    ""
  ];
  for (const segment of derived.narration_segments) {
    const beat = derived.beats.find((candidate) => candidate.beat_id === segment.beat_id) || {};
    lines.push(
      `## Beat ${beat.beat_number}: ${beat.title_ja}`,
      "",
      `- beat_id: ${segment.beat_id}`,
      `- segment_id: ${segment.segment_id}`,
      `- timing: ${segment.start_time}-${segment.end_time}`,
      `- status: ${segment.status}`,
      `- character_count_estimate: ${segment.character_count_estimate}`,
      `- reading_seconds_estimate: ${segment.reading_seconds_estimate}`,
      "",
      segment.text,
      "",
      "Held truth notes:",
      ...segment.held_truth_notes.map((note) => `- ${note}`),
      ""
    );
  }
  return `${lines.join("\n").trimEnd()}\n`;
}

function renderEditorialDerivativeCsv(records, headers) {
  const rows = [headers.join(",")];
  for (const record of records) {
    rows.push(headers.map((header) => editorialDerivativeCsvField(record?.[header])).join(","));
  }
  return `${rows.join("\n")}\n`;
}

function editorialDerivativeCsvField(value) {
  const text = value === null || value === undefined ? "" : String(value);
  if (!/[",\r\n]/.test(text)) {
    return text;
  }
  return `"${text.replace(/"/g, '""')}"`;
}

function buildEditorialDerivativeProvenance(
  derived,
  sourceHandoff,
  revisionPatch,
  patchSha256,
  coreFiles,
  coreFingerprint
) {
  const changes = revisionPatch.accepted_changes.map((change) => {
    const expected = EDITORIAL_DERIVATIVE_EXPECTED_CHANGES.find((item) =>
      item.change_id === change.change_id
    );
    return {
      change_id: change.change_id,
      beat_id: change.beat_id,
      target_type: change.target_type,
      target_id: change.target_id,
      target_field: change.target_field,
      guard_class: change.guard_class,
      before: cloneJsonValue(change.before),
      before_sha256: editorialRevisionValueHash(change.before),
      after: cloneJsonValue(change.proposed_value),
      after_sha256: editorialRevisionValueHash(change.proposed_value),
      derived_file_locations: cloneJsonValue(expected?.derived_file_locations || [])
    };
  });
  const coreFileEntries = EDITORIAL_DERIVATIVE_CORE_FILES.map((relativePath) => ({
    relative_path: relativePath,
    byte_size: coreFiles[relativePath].byteLength,
    sha256: editorialDerivativeBufferHash(coreFiles[relativePath])
  }));
  return {
    schemaVersion: EDITORIAL_DERIVATIVE_PROVENANCE_SCHEMA_VERSION,
    artifact_id: EDITORIAL_DERIVATIVE_ARTIFACT_ID,
    generatedAt: revisionPatch.created_at,
    status: "derived_revision_preview",
    canonical: false,
    source: {
      artifact_id: EDITORIAL_REVISION_SOURCE_ARTIFACT_ID,
      editorial_handoff_sha256: EDITORIAL_REVISION_SOURCE_HANDOFF_SHA256,
      package_manifest_sha256: EDITORIAL_REVISION_SOURCE_MANIFEST_SHA256
    },
    patch: {
      patch_id: revisionPatch.patch_id,
      path: EDITORIAL_DERIVATIVE_PATCH_PATH,
      sha256: patchSha256
    },
    derivative: {
      artifact_id: derived.artifact_id,
      editorial_handoff_sha256: editorialDerivativeBufferHash(
        coreFiles["editorial-handoff.derived.json"]
      ),
      core_fingerprint_sha256: coreFingerprint,
      core_fingerprint_algorithm: "sha256 of LF-joined ordered relative_path:sha256 pairs for the five core files"
    },
    source_apply_status: "not_applied",
    derived_apply_status: "applied_to_derived_copy",
    application_scope: "derived_copy_only",
    rollback_action: "discard_derived_package",
    applied_change_count: 3,
    content_delta_count: 3,
    changes,
    core_files: coreFileEntries,
    invariants: {
      source_package_unchanged: true,
      revision_package_unchanged: true,
      beat_order_unchanged: true,
      timing_unchanged: true,
      canon_unchanged: true,
      truth_state_unchanged: true,
      rights_unchanged: true,
      assets_unchanged: true,
      beat_count: sourceHandoff.beats.length,
      total_duration_seconds: sourceHandoff.total_duration_seconds,
      narration_segment_count: sourceHandoff.narration_segments.length,
      subtitle_cue_count: sourceHandoff.subtitle_cues.length,
      shot_cue_count: sourceHandoff.shot_cues.length,
      thumbnail_direction_count: sourceHandoff.thumbnail_directions.length,
      narration_character_count_before: 777,
      narration_character_count_after: 778
    },
    boundaries: editorialDerivativeClosedBoundaries()
  };
}

function renderEditorialDerivativeReadme(derived, provenance) {
  const lines = [
    "# Fast Fiction Factory Editorial Derivative Preview",
    "",
    "**DERIVED PREVIEW / NOT CANONICAL**",
    "",
    `Artifact: \`${derived.artifact_id}\``,
    "",
    "This local package applies exactly three accepted safe wording edits to a copy of the immutable Editorial Handoff package. It is not final, approved, canonical, rights-cleared, production-ready, rendered, uploaded, published, or persisted to a database.",
    "",
    "## Application contract",
    "",
    `- source_apply_status: \`${derived.source_apply_status}\``,
    `- derived_apply_status: \`${derived.derived_apply_status}\``,
    `- application_scope: \`${derived.application_scope}\``,
    `- rollback_action: \`${derived.rollback_action}\``,
    `- applied changes: \`${derived.applied_changes.length}\``,
    "- rollback: discard this entire derived package; no source file was modified.",
    "",
    "## Fingerprints",
    "",
    `- source editorial-handoff.json: \`${provenance.source.editorial_handoff_sha256}\``,
    `- source package-manifest.json: \`${provenance.source.package_manifest_sha256}\``,
    `- accepted patch: \`${provenance.patch.sha256}\``,
    `- derived editorial JSON: \`${provenance.derivative.editorial_handoff_sha256}\``,
    `- derived core fingerprint: \`${provenance.derivative.core_fingerprint_sha256}\``,
    "",
    "## Package files",
    "",
    ...EDITORIAL_DERIVATIVE_REQUIRED_FILES.map((relativePath) => `- \`${relativePath}\``),
    "",
    "The manifest inventories the other seven files and intentionally has no self-hash. The core fingerprint is SHA256 over LF-joined ordered `relative_path:sha256` pairs for narration, subtitle, shot, derived JSON, and the byte-identical accepted patch.",
    "",
    "## Closed boundaries",
    "",
    "Timing, beat order, truth, ending, canon, rights, assets, provider/API, credentials, external calls, generation, render, upload/publication, and database persistence remain unchanged or closed.",
    ""
  ];
  return `${lines.join("\n").trimEnd()}\n`;
}

function buildEditorialDerivativePackageManifest(
  derived,
  revisionPatch,
  patchSha256,
  packageFiles,
  coreFingerprint
) {
  const files = EDITORIAL_DERIVATIVE_PACKAGE_FILES.map((relativePath) => ({
    relative_path: relativePath,
    byte_size: packageFiles[relativePath].byteLength,
    sha256: editorialDerivativeBufferHash(packageFiles[relativePath])
  }));
  return {
    schemaVersion: EDITORIAL_DERIVATIVE_PACKAGE_MANIFEST_SCHEMA_VERSION,
    artifact_id: EDITORIAL_DERIVATIVE_ARTIFACT_ID,
    generatedAt: revisionPatch.created_at,
    package_root: EDITORIAL_DERIVATIVE_PACKAGE_ROOT,
    status: "derived_revision_preview",
    canonical: false,
    source: cloneJsonValue(derived.source),
    patch: {
      patch_id: revisionPatch.patch_id,
      path: EDITORIAL_DERIVATIVE_PATCH_PATH,
      sha256: patchSha256
    },
    derivative_core_fingerprint_sha256: coreFingerprint,
    files,
    passed: files.length === EDITORIAL_DERIVATIVE_PACKAGE_FILES.length
  };
}

function editorialDerivativeCoreFingerprint(files) {
  const material = EDITORIAL_DERIVATIVE_CORE_FILES.map((relativePath) =>
    `${relativePath}:${editorialDerivativeBufferHash(files[relativePath])}`
  ).join("\n") + "\n";
  return editorialDerivativeBufferHash(Buffer.from(material, "utf8"));
}

function editorialDerivativeJsonBuffer(value) {
  return Buffer.from(`${JSON.stringify(value, null, 2)}\n`, "utf8");
}

function editorialDerivativeUtf8(value) {
  return Buffer.from(value, "utf8");
}

function editorialDerivativeBufferHash(value) {
  return createHash("sha256").update(value).digest("hex");
}

function editorialDerivativeClosedBoundaries() {
  return {
    local_only: true,
    external_call: false,
    provider_configured: false,
    credentials_touched: false,
    public_upload: false,
    ai_video_generation: false,
    production_render: false,
    database_persistence: false,
    final_canon_decision: false,
    rights_cleared_claim: false
  };
}

function validateEditorialDerivativePackageCandidate(filesInput, context) {
  const errors = [];
  const files = {};
  for (const [relativePath, value] of Object.entries(filesInput || {})) {
    files[relativePath] = Buffer.isBuffer(value) ? value : Buffer.from(String(value ?? ""), "utf8");
  }
  const actualPaths = Object.keys(files).sort();
  const requiredPaths = [...EDITORIAL_DERIVATIVE_REQUIRED_FILES].sort();
  if (!arrayEqualsExact(actualPaths, requiredPaths)) {
    errors.push(`package file set mismatch: ${actualPaths.join(",")}`);
  }
  const missing = EDITORIAL_DERIVATIVE_REQUIRED_FILES.filter((relativePath) =>
    !files[relativePath] || files[relativePath].byteLength === 0
  );
  if (missing.length > 0) {
    errors.push(`missing package files: ${missing.join(",")}`);
    return { valid: false, errors };
  }

  const parsePackageJson = (relativePath) => {
    try {
      return JSON.parse(files[relativePath].toString("utf8"));
    } catch (error) {
      errors.push(`${relativePath}: invalid JSON: ${error.message}`);
      return null;
    }
  };
  const derived = parsePackageJson("editorial-handoff.derived.json");
  const appliedPatch = parsePackageJson("applied-revision-patch.json");
  const provenance = parsePackageJson("derivative-provenance.json");
  const manifest = parsePackageJson("derivative-package-manifest.json");
  if (!derived || !appliedPatch || !provenance || !manifest) {
    return { valid: false, errors };
  }

  const sourceHandoff = context?.source_handoff || {};
  const revisionPatch = context?.revision_patch || {};
  const patchSha256 = context?.patch_sha256 || null;
  const sourceFingerprint = context?.source_fingerprint || {};
  const patchInputValidation = validateEditorialDerivativePatchInput(
    appliedPatch,
    editorialDerivativeBufferHash(files["applied-revision-patch.json"]),
    sourceHandoff,
    sourceFingerprint
  );
  if (!patchInputValidation.valid) {
    errors.push(...patchInputValidation.errors.map((error) => `applied patch: ${error}`));
  }
  if (!jsonValuesEqual(appliedPatch, revisionPatch) ||
      editorialDerivativeBufferHash(files["applied-revision-patch.json"]) !== patchSha256) {
    errors.push("applied-revision-patch.json must be a byte-identical copy of the accepted source patch");
  }

  const identityValid =
    derived.schemaVersion === EDITORIAL_DERIVATIVE_PREVIEW_SCHEMA_VERSION &&
    derived.artifact_id === EDITORIAL_DERIVATIVE_ARTIFACT_ID &&
    derived.generatedAt === revisionPatch.created_at &&
    derived.status === "derived_revision_preview" &&
    derived.derived_status === "derived_revision_preview" &&
    derived.canonical === false &&
    derived.source_apply_status === "not_applied" &&
    derived.derived_apply_status === "applied_to_derived_copy" &&
    derived.application_scope === "derived_copy_only" &&
    derived.rollback_action === "discard_derived_package" &&
    derived.review_route === "public/review/index.html?mode=derivative" &&
    editorialRevisionSourceMatches(derived.source, sourceFingerprint) &&
    derived.patch?.patch_id === revisionPatch.patch_id &&
    derived.patch?.path === EDITORIAL_DERIVATIVE_PATCH_PATH &&
    derived.patch?.sha256 === patchSha256 &&
    derived.selected_candidate_id === EDITORIAL_REVISION_CANDIDATE_ID &&
    derived.selected_channel_route_id === EDITORIAL_REVISION_CHANNEL_ID &&
    editorialRevisionBoundariesClosed(derived);
  if (!identityValid) {
    errors.push("derived JSON identity, application semantics, source, patch, route, or boundaries invalid");
  }
  const modelAudit = auditEditorialDerivativeModel(sourceHandoff, derived, revisionPatch);
  errors.push(...modelAudit.errors.map((error) => `derived model: ${error}`));

  const expectedNarration = renderEditorialDerivativeNarration(derived);
  if (files["narration-script.derived.md"].toString("utf8") !== expectedNarration) {
    errors.push("narration Markdown does not exactly match the derived JSON model");
  }
  const expectedSubtitleCsv = renderEditorialDerivativeCsv(
    derived.subtitle_cues,
    editorialDerivativeSubtitleHeaders()
  );
  if (files["subtitle-cues.derived.csv"].toString("utf8") !== expectedSubtitleCsv) {
    errors.push("subtitle CSV does not exactly match the derived JSON model");
  }
  const expectedShotCsv = renderEditorialDerivativeCsv(
    derived.shot_cues,
    editorialDerivativeShotHeaders()
  );
  if (files["shot-list.derived.csv"].toString("utf8") !== expectedShotCsv) {
    errors.push("shot CSV does not exactly match the derived JSON model");
  }
  try {
    const subtitleCsv = parseCsvText(files["subtitle-cues.derived.csv"].toString("utf8"));
    if (!arrayEqualsExact(subtitleCsv.headers, editorialDerivativeSubtitleHeaders()) ||
        !csvRecordsMatchObjects(
          subtitleCsv.records,
          derived.subtitle_cues,
          editorialDerivativeSubtitleHeaders()
        )) {
      errors.push("subtitle CSV headers or rows fail structured cross-match");
    }
  } catch (error) {
    errors.push(`subtitle CSV parse failed: ${error.message}`);
  }
  try {
    const shotCsv = parseCsvText(files["shot-list.derived.csv"].toString("utf8"));
    if (!arrayEqualsExact(shotCsv.headers, editorialDerivativeShotHeaders()) ||
        !csvRecordsMatchObjects(
          shotCsv.records,
          derived.shot_cues,
          editorialDerivativeShotHeaders()
        )) {
      errors.push("shot CSV headers or rows fail structured cross-match");
    }
  } catch (error) {
    errors.push(`shot CSV parse failed: ${error.message}`);
  }

  const coreFingerprint = editorialDerivativeCoreFingerprint(files);
  const expectedProvenance = buildEditorialDerivativeProvenance(
    derived,
    sourceHandoff,
    revisionPatch,
    patchSha256,
    files,
    coreFingerprint
  );
  if (!jsonValuesEqual(provenance, expectedProvenance)) {
    errors.push("derivative provenance is incomplete or does not match source, patch, deltas, or core hashes");
  }
  const expectedReadme = renderEditorialDerivativeReadme(derived, expectedProvenance);
  if (files["README_DERIVATIVE.md"].toString("utf8") !== expectedReadme) {
    errors.push("README_DERIVATIVE.md does not match the deterministic package contract");
  }
  const packageWithoutManifest = Object.fromEntries(
    EDITORIAL_DERIVATIVE_PACKAGE_FILES.map((relativePath) => [relativePath, files[relativePath]])
  );
  const expectedManifest = buildEditorialDerivativePackageManifest(
    derived,
    revisionPatch,
    patchSha256,
    packageWithoutManifest,
    coreFingerprint
  );
  if (!jsonValuesEqual(manifest, expectedManifest)) {
    errors.push("derivative package manifest does not match byte sizes, hashes, source, patch, or core fingerprint");
  }
  const manifestPaths = Array.isArray(manifest?.files)
    ? manifest.files.map((entry) => String(entry?.relative_path || ""))
    : [];
  if (manifestPaths.length !== EDITORIAL_DERIVATIVE_PACKAGE_FILES.length ||
      !arrayEqualsExact(manifestPaths, EDITORIAL_DERIVATIVE_PACKAGE_FILES) ||
      manifestPaths.includes("derivative-package-manifest.json")) {
    errors.push("manifest must inventory exactly the other seven files and no self-hash");
  }
  return {
    valid: errors.length === 0,
    errors,
    derived,
    provenance,
    manifest,
    audit: modelAudit,
    core_fingerprint_sha256: coreFingerprint
  };
}

async function writeEditorialDerivativePackageArtifacts(files) {
  const actualPaths = Object.keys(files || {}).sort();
  const allowedPaths = [...EDITORIAL_DERIVATIVE_REQUIRED_FILES].sort();
  if (!arrayEqualsExact(actualPaths, allowedPaths)) {
    fail(`Refusing derivative write outside exact package set: ${actualPaths.join(",")}`);
  }
  await mkdir(EDITORIAL_DERIVATIVE_PACKAGE_ROOT, { recursive: true });
  for (const relativePath of EDITORIAL_DERIVATIVE_REQUIRED_FILES) {
    const target = `${EDITORIAL_DERIVATIVE_PACKAGE_ROOT}/${relativePath}`;
    if (toRepoPath(target) !== `${EDITORIAL_DERIVATIVE_PACKAGE_ROOT}/${relativePath}`) {
      fail(`Refusing unsafe derivative target: ${target}`);
    }
    await writeFile(target, files[relativePath]);
  }
}

async function snapshotEditorialDerivativeProtectedFiles() {
  const paths = [
    ...EDITORIAL_HANDOFF_REQUIRED_FILES.map((relativePath) =>
      `${EDITORIAL_HANDOFF_PACKAGE_ROOT}/${relativePath}`
    ),
    ...EDITORIAL_REVISION_REQUIRED_FILES.map((relativePath) =>
      `${EDITORIAL_REVISION_PACKAGE_ROOT}/${relativePath}`
    )
  ];
  const entries = await Promise.all(paths.map(async (filePath) => {
    const snapshot = await readFileSnapshot(filePath);
    return [filePath, {
      exists: snapshot.exists,
      byte_size: snapshot.byteSize,
      sha256: snapshot.sha256
    }];
  }));
  return Object.fromEntries(entries);
}

function editorialDerivativeSnapshotMapsEqual(left, right) {
  return JSON.stringify(left) === JSON.stringify(right);
}

async function readEditorialDerivativeSmokeSeed(inputPath, targetPath) {
  if (path.resolve(inputPath) !== path.resolve(targetPath) && await fileSizeOrZero(inputPath) > 0) {
    return readJson(inputPath);
  }
  return {
    schemaVersion: EDITORIAL_DERIVATIVE_PREVIEW_SCHEMA_VERSION,
    artifact_id: EDITORIAL_DERIVATIVE_ARTIFACT_ID,
    derivative_route: "public/review/index.html?mode=derivative",
    revision_route: "public/review/index.html?mode=revision",
    handoff_route: "public/review/index.html?mode=handoff",
    bridge_route: "public/review/index.html?mode=bridge",
    brief_route: "public/review/index.html?mode=brief",
    source: {
      artifact_id: EDITORIAL_REVISION_SOURCE_ARTIFACT_ID,
      editorial_handoff_sha256: EDITORIAL_REVISION_SOURCE_HANDOFF_SHA256,
      package_manifest_sha256: EDITORIAL_REVISION_SOURCE_MANIFEST_SHA256
    },
    patch: {
      path: EDITORIAL_DERIVATIVE_PATCH_PATH,
      sha256: EDITORIAL_DERIVATIVE_PATCH_SHA256
    },
    derived_status: "derived_revision_preview",
    source_apply_status: "not_applied",
    derived_apply_status: "applied_to_derived_copy",
    application_scope: "derived_copy_only",
    rollback_action: "discard_derived_package",
    boundaries: editorialDerivativeClosedBoundaries(),
    failures: [],
    passed: true
  };
}

function cloneEditorialDerivativeFiles(files) {
  return Object.fromEntries(Object.entries(files).map(([relativePath, buffer]) => [
    relativePath,
    Buffer.from(buffer)
  ]));
}

function mutateEditorialDerivativeJsonFile(files, relativePath, mutate) {
  const clone = cloneEditorialDerivativeFiles(files);
  const value = JSON.parse(clone[relativePath].toString("utf8"));
  mutate(value);
  clone[relativePath] = editorialDerivativeJsonBuffer(value);
  return clone;
}

function editorialRevisionSourceMatches(value, expected) {
  return value?.artifact_id === expected.artifact_id &&
    value?.editorial_handoff_sha256 === expected.editorial_handoff_sha256 &&
    value?.package_manifest_sha256 === expected.package_manifest_sha256;
}

function editorialRevisionBoundariesClosed(value) {
  const boundary = (key) => value?.[key] ?? value?.boundaries?.[key];
  return boundary("local_only") === true &&
    boundary("external_call") === false &&
    boundary("provider_configured") === false &&
    boundary("credentials_touched") === false &&
    boundary("public_upload") === false &&
    boundary("ai_video_generation") === false &&
    boundary("production_render") === false &&
    boundary("database_persistence") === false &&
    boundary("final_canon_decision") === false &&
    boundary("rights_cleared_claim") === false;
}

function validateEditorialRevisionTemplate(template, sourceFingerprint) {
  const errors = [];
  const contract = template?.change_contract || {};
  const requiredChangeFields = [
    "change_id",
    "beat_id",
    "target_type",
    "target_id",
    "target_field",
    "change_type",
    "before",
    "proposed_value",
    "rationale",
    "requested_status"
  ];
  if (template?.schemaVersion !== EDITORIAL_REVISION_REQUEST_SCHEMA_VERSION) {
    errors.push("template schemaVersion mismatch");
  }
  if (!editorialRevisionSourceMatches(template?.source, sourceFingerprint)) {
    errors.push("template source fingerprint mismatch");
  }
  if (template?.candidate_id !== EDITORIAL_REVISION_CANDIDATE_ID ||
      template?.channel_id !== EDITORIAL_REVISION_CHANNEL_ID) {
    errors.push("template candidate or channel mismatch");
  }
  if (!Array.isArray(template?.changes) || template.changes.length !== 0) {
    errors.push("template changes must start empty");
  }
  if (!requiredChangeFields.every((field) => contract?.required_fields?.includes(field))) {
    errors.push("template required_fields are incomplete");
  }
  if (!arraySetEquals(contract?.safe_local_edit_types, EDITORIAL_REVISION_SAFE_TYPES)) {
    errors.push("template safe_local_edit_types mismatch");
  }
  if (!arraySetEquals(contract?.human_author_required_types, EDITORIAL_REVISION_HUMAN_TYPES)) {
    errors.push("template human_author_required_types mismatch");
  }
  if (!arraySetEquals(contract?.blocked_boundary_types, EDITORIAL_REVISION_BLOCKED_TYPES)) {
    errors.push("template blocked_boundary_types mismatch");
  }
  if (contract?.unknown_values !== "fail_closed") {
    errors.push("template unknown_values must fail_closed");
  }
  if (!editorialRevisionBoundariesClosed(template)) {
    errors.push("template boundaries are not closed");
  }
  return { valid: errors.length === 0, errors };
}

function validateEditorialRevisionRequestPayload(request, sourceHandoff, sourceFingerprint) {
  const errors = [];
  const changes = Array.isArray(request?.changes) ? request.changes : [];
  const sourceValid = editorialRevisionSourceMatches(request?.source, sourceFingerprint);
  const requiredFields = [
    "change_id",
    "beat_id",
    "target_type",
    "target_id",
    "target_field",
    "change_type",
    "proposed_value",
    "rationale",
    "requested_status"
  ];
  if (request?.schemaVersion !== EDITORIAL_REVISION_REQUEST_SCHEMA_VERSION) {
    errors.push("request schemaVersion mismatch");
  }
  if (!hasNonEmptyText(request?.request_id) ||
      !hasNonEmptyText(request?.requested_by) ||
      !hasNonEmptyText(request?.created_at) ||
      Number.isNaN(Date.parse(request?.created_at))) {
    errors.push("request identity or timestamp invalid");
  }
  if (!sourceValid) {
    errors.push("request source identity or fingerprint mismatch");
  }
  if (request?.candidate_id !== EDITORIAL_REVISION_CANDIDATE_ID ||
      request?.channel_id !== EDITORIAL_REVISION_CHANNEL_ID) {
    errors.push("request candidate or channel mismatch");
  }
  if (changes.length !== 6) {
    errors.push("request must contain exactly six changes");
  }
  if (!editorialRevisionBoundariesClosed(request)) {
    errors.push("request boundaries are not closed");
  }

  const sourceBeatIds = new Set(
    (Array.isArray(sourceHandoff?.beats) ? sourceHandoff.beats : [])
      .map((beat) => String(beat?.beat_id || ""))
      .filter(Boolean)
  );
  const changeIds = changes.map((change) => String(change?.change_id || ""));
  if (changeIds.some((id) => !id) || new Set(changeIds).size !== changeIds.length) {
    errors.push("change_id values must be non-empty and unique");
  }
  const changeBeatIds = changes.map((change) => String(change?.beat_id || ""));
  if (changeBeatIds.some((beatId) => !sourceBeatIds.has(beatId))) {
    errors.push("every change must reference a source beat");
  }
  if (new Set(changeBeatIds).size !== 6 ||
      sourceBeatIds.size !== 6 ||
      ![...sourceBeatIds].every((beatId) => changeBeatIds.includes(beatId))) {
    errors.push("example request must associate exactly one change with each source beat");
  }

  const classifications = [];
  for (const [index, change] of changes.entries()) {
    const label = String(change?.change_id || "change[" + index + "]");
    for (const field of requiredFields) {
      if (!Object.prototype.hasOwnProperty.call(change || {}, field) ||
          (typeof change?.[field] === "string" && change[field].trim().length === 0)) {
        errors.push(label + ": missing " + field);
      }
    }
    const hasBefore = Object.prototype.hasOwnProperty.call(change || {}, "before");
    const hasBeforeHash = /^[a-f0-9]{64}$/i.test(String(change?.before_hash || ""));
    if (!hasBefore && !hasBeforeHash) {
      errors.push(label + ": before value or before_hash is required");
    }
    if (change?.requested_status !== "proposed") {
      errors.push(label + ": requested_status must be proposed");
    }
    const sourceTarget = resolveEditorialRevisionSourceTarget(sourceHandoff, change);
    if (!sourceTarget.found) {
      errors.push(label + ": " + sourceTarget.error);
    } else {
      const beforeMatches = hasBefore
        ? jsonValuesEqual(change.before, sourceTarget.value)
        : change.before_hash.toLowerCase() === editorialRevisionValueHash(sourceTarget.value);
      if (!beforeMatches) {
        errors.push(label + ": before value or hash does not match immutable source");
      }
      if (sourceTarget.beat_id && sourceTarget.beat_id !== change?.beat_id) {
        errors.push(label + ": target beat does not match change beat");
      }
    }
    const classification = classifyEditorialRevisionChange(change, {
      sourceIdentityValid: sourceValid,
      sourceTargetFound: sourceTarget.found
    });
    classifications.push({
      change_id: label,
      guard_class: classification.guard_class,
      reason: classification.reason
    });
    if (change?.derived_guard_class !== classification.guard_class) {
      errors.push(label + ": derived_guard_class mismatch; expected " + classification.guard_class);
    }
    if (!EDITORIAL_REVISION_SAFE_TYPES.has(change?.change_type) &&
        !EDITORIAL_REVISION_HUMAN_TYPES.has(change?.change_type) &&
        !EDITORIAL_REVISION_BLOCKED_TYPES.has(change?.change_type)) {
      errors.push(label + ": unknown change_type fails closed");
    }
  }

  const guardCounts = countGuardClasses(classifications);
  const expectedReadback = request?.expected_readback || {};
  if (expectedReadback?.change_count !== 6 ||
      expectedReadback?.guard_counts?.safe_local_edit !== 3 ||
      expectedReadback?.guard_counts?.human_author_required !== 1 ||
      expectedReadback?.guard_counts?.blocked_boundary !== 2 ||
      expectedReadback?.unknown_values !== "fail_closed") {
    errors.push("request expected_readback mismatch");
  }
  return {
    valid: errors.length === 0,
    errors,
    change_count: changes.length,
    guard_counts: guardCounts,
    classifications
  };
}

function resolveEditorialRevisionSourceTarget(sourceHandoff, change) {
  const targetType = String(change?.target_type || "");
  const targetId = String(change?.target_id || "");
  const targetField = String(change?.target_field || "");
  const specs = {
    narration_segment: ["narration_segments", "segment_id"],
    subtitle_cue: ["subtitle_cues", "cue_id"],
    shot_cue: ["shot_cues", "shot_id"],
    beat: ["beats", "beat_id"],
    truth_guard: ["truth_guards", "guard_id"]
  };
  const spec = specs[targetType];
  if (!spec) {
    return { found: false, error: "unknown target_type " + (targetType || "<empty>") };
  }
  const [collectionName, idKey] = spec;
  const item = (Array.isArray(sourceHandoff?.[collectionName]) ? sourceHandoff[collectionName] : [])
    .find((candidate) => String(candidate?.[idKey] || "") === targetId);
  if (!item) {
    return { found: false, error: "unknown target_id " + (targetId || "<empty>") };
  }
  let value;
  if (targetType === "beat" && targetField === "time_window") {
    value = {
      start_time: item.start_time,
      end_time: item.end_time,
      start_seconds: item.start_seconds,
      end_seconds: item.end_seconds
    };
  } else if (Object.prototype.hasOwnProperty.call(item, targetField)) {
    value = item[targetField];
  } else {
    return { found: false, error: "unknown target_field " + (targetField || "<empty>") };
  }
  return {
    found: true,
    value,
    beat_id: targetType === "beat" ? item.beat_id : item.beat_id || null
  };
}

function classifyEditorialRevisionChange(change, options = {}) {
  if (options.sourceIdentityValid !== true) {
    return {
      guard_class: "blocked_boundary",
      reason: "source identity or fingerprint mismatch"
    };
  }
  if (options.sourceTargetFound !== true) {
    return {
      guard_class: "blocked_boundary",
      reason: "unknown target fails closed"
    };
  }
  const changeType = String(change?.change_type || "");
  const targetType = String(change?.target_type || "");
  const targetField = String(change?.target_field || "");
  if (editorialRevisionTextIsUnsafe(change?.proposed_value)) {
    return {
      guard_class: "blocked_boundary",
      reason: "proposed text claims a closed canon, rights, asset, provider, generation, render, upload, publication, or persistence boundary"
    };
  }
  if (EDITORIAL_REVISION_BLOCKED_TYPES.has(changeType)) {
    return {
      guard_class: "blocked_boundary",
      reason: "change_type is a closed production or authority boundary"
    };
  }
  if (EDITORIAL_REVISION_HUMAN_TYPES.has(changeType)) {
    const humanTargetValid =
      (changeType === "beat_timing" &&
        targetType === "beat" &&
        ["time_window", "start_time", "end_time", "start_seconds", "end_seconds", "duration_seconds"].includes(targetField)) ||
      (changeType === "beat_order" &&
        targetType === "beat" &&
        ["beat_number", "order", "sequence"].includes(targetField)) ||
      (["story_truth", "ending_choice"].includes(changeType) &&
        targetType === "truth_guard" &&
        ["state", "status", "safe_rule", "choice"].includes(targetField));
    return humanTargetValid
      ? {
          guard_class: "human_author_required",
          reason: "timing, order, story truth, or ending remains human-author-owned"
        }
      : {
          guard_class: "blocked_boundary",
          reason: "human-author change_type uses an incompatible protected target"
        };
  }
  if (EDITORIAL_REVISION_SAFE_TYPES.has(changeType)) {
    const safeTargetTuples = {
      narration_wording: ["narration_segment", "text"],
      subtitle_wording: ["subtitle_cue", "text_ja"],
      shot_direction_wording: ["shot_cue", "visual_direction"]
    };
    const [safeTargetType, safeTargetField] = safeTargetTuples[changeType];
    if (targetType !== safeTargetType || targetField !== safeTargetField) {
      return {
        guard_class: "blocked_boundary",
        reason: "safe wording type is restricted to its exact source text field"
      };
    }
    return {
      guard_class: "safe_local_edit",
      reason: "wording-only change on an exact allowed text target"
    };
  }
  return {
    guard_class: "blocked_boundary",
    reason: "unknown change_type fails closed"
  };
}

function editorialRevisionTextIsUnsafe(value) {
  const text = typeof value === "string" ? value : JSON.stringify(value ?? "");
  return /final[_\s-]?canon|canon(?:ical)?[_\s-]?(?:final|approved)|rights?[_\s-]?(?:cleared|approved)|selected\s*:|asset[_\s-]?selected|provider[_\s/-]?api|api[_\s-]?key|credential|external[_\s-]?model|production[_\s-]?render|rendered|uploaded|published|database[_\s-]?(?:write|persist)|最終(?:カノン|正史)|正史(?:に)?(?:確定|昇格)|権利(?:確認済み|処理済み|クリア)|素材(?:を)?(?:選定|確定)|プロバイダ|認証情報|生成済み|レンダー済み|アップロード済み|公開済み/i.test(text);
}

function validateEditorialRevisionDecisionPayload(decision, request, requestValidation, sourceFingerprint) {
  const errors = [];
  const decisions = Array.isArray(decision?.decisions) ? decision.decisions : [];
  const requestChanges = Array.isArray(request?.changes) ? request.changes : [];
  const classificationById = new Map(
    requestValidation.classifications.map((item) => [item.change_id, item.guard_class])
  );
  if (decision?.schemaVersion !== EDITORIAL_REVISION_DECISION_SCHEMA_VERSION) {
    errors.push("decision schemaVersion mismatch");
  }
  if (!hasNonEmptyText(decision?.decision_id) ||
      decision?.request_id !== request?.request_id ||
      !hasNonEmptyText(decision?.decided_by) ||
      !hasNonEmptyText(decision?.decided_at) ||
      Number.isNaN(Date.parse(decision?.decided_at))) {
    errors.push("decision identity, request, or timestamp invalid");
  }
  if (!editorialRevisionSourceMatches(decision?.source, sourceFingerprint)) {
    errors.push("decision source fingerprint mismatch");
  }
  if (decision?.candidate_id !== EDITORIAL_REVISION_CANDIDATE_ID ||
      decision?.channel_id !== EDITORIAL_REVISION_CHANNEL_ID) {
    errors.push("decision candidate or channel mismatch");
  }
  if (decision?.apply_status !== "not_applied") {
    errors.push("decision apply_status must be not_applied");
  }
  if (!editorialRevisionBoundariesClosed(decision)) {
    errors.push("decision boundaries are not closed");
  }
  const ids = decisions.map((item) => String(item?.change_id || ""));
  const requestIds = requestChanges.map((item) => String(item?.change_id || ""));
  if (decisions.length !== requestChanges.length ||
      new Set(ids).size !== ids.length ||
      !requestIds.every((id) => ids.includes(id)) ||
      !ids.every((id) => requestIds.includes(id))) {
    errors.push("decisions must cover each request change exactly once");
  }
  const allowedDecisionByClass = {
    safe_local_edit: new Set(["accept", "hold", "reject", "return"]),
    human_author_required: new Set(["hold", "return"]),
    blocked_boundary: new Set(["reject", "return"])
  };
  for (const item of decisions) {
    const id = String(item?.change_id || "");
    const expectedClass = classificationById.get(id);
    if (item?.guard_class !== expectedClass) {
      errors.push(id + ": decision guard_class mismatch");
    }
    if (!allowedDecisionByClass[expectedClass]?.has(item?.decision)) {
      errors.push(id + ": decision " + item?.decision + " is not allowed for " + expectedClass);
    }
    if (!hasNonEmptyText(item?.rationale)) {
      errors.push(id + ": decision rationale missing");
    }
  }
  const decisionCounts = {
    accept: decisions.filter((item) => item?.decision === "accept").length,
    hold: decisions.filter((item) => item?.decision === "hold").length,
    reject: decisions.filter((item) => item?.decision === "reject").length,
    return: decisions.filter((item) => item?.decision === "return").length
  };
  if (!["accept", "hold", "reject", "return"].every((name) =>
    decision?.decision_counts?.[name] === decisionCounts[name]
  )) {
    errors.push("declared decision_counts do not match decisions");
  }
  if (decisionCounts.accept !== 3 ||
      decisionCounts.hold !== 1 ||
      decisionCounts.reject !== 2 ||
      decisionCounts.return !== 0) {
    errors.push("example decisions must be exactly 3 accept / 1 hold / 2 reject");
  }
  return {
    valid: errors.length === 0,
    errors,
    decision_counts: decisionCounts
  };
}

function validateEditorialRevisionPatchPayload(
  revisionPatch,
  request,
  decision,
  requestValidation,
  sourceFingerprint
) {
  const errors = [];
  const changes = Array.isArray(request?.changes) ? request.changes : [];
  const acceptedChanges = Array.isArray(revisionPatch?.accepted_changes)
    ? revisionPatch.accepted_changes
    : [];
  const decisionById = new Map(
    (Array.isArray(decision?.decisions) ? decision.decisions : [])
      .map((item) => [String(item?.change_id || ""), item])
  );
  const classificationById = new Map(
    requestValidation.classifications.map((item) => [item.change_id, item.guard_class])
  );
  const expectedAccepted = changes.filter((change) =>
    classificationById.get(String(change?.change_id || "")) === "safe_local_edit" &&
    decisionById.get(String(change?.change_id || ""))?.decision === "accept"
  );
  if (revisionPatch?.schemaVersion !== EDITORIAL_REVISION_PATCH_SCHEMA_VERSION) {
    errors.push("patch schemaVersion mismatch");
  }
  if (!hasNonEmptyText(revisionPatch?.patch_id) ||
      revisionPatch?.request_id !== request?.request_id ||
      revisionPatch?.decision_id !== decision?.decision_id ||
      !hasNonEmptyText(revisionPatch?.created_at) ||
      Number.isNaN(Date.parse(revisionPatch?.created_at))) {
    errors.push("patch identity, linkage, or timestamp invalid");
  }
  if (!editorialRevisionSourceMatches(revisionPatch?.source, sourceFingerprint)) {
    errors.push("patch source fingerprint mismatch");
  }
  if (revisionPatch?.candidate_id !== EDITORIAL_REVISION_CANDIDATE_ID ||
      revisionPatch?.channel_id !== EDITORIAL_REVISION_CHANNEL_ID) {
    errors.push("patch candidate or channel mismatch");
  }
  if (revisionPatch?.apply_status !== "not_applied") {
    errors.push("patch apply_status must be not_applied");
  }
  const unchangedFlags = [
    "source_package_unchanged",
    "beat_order_unchanged",
    "timing_unchanged",
    "canon_unchanged",
    "rights_state_unchanged",
    "asset_state_unchanged",
    "production_gates_closed"
  ];
  if (!unchangedFlags.every((field) => revisionPatch?.[field] === true)) {
    errors.push("patch unchanged and production-gate flags must all be true");
  }
  if (!editorialRevisionBoundariesClosed(revisionPatch)) {
    errors.push("patch boundaries are not closed");
  }
  const acceptedIds = acceptedChanges.map((item) => String(item?.change_id || ""));
  const expectedIds = expectedAccepted.map((item) => String(item?.change_id || ""));
  if (acceptedChanges.length !== 3 ||
      new Set(acceptedIds).size !== acceptedIds.length ||
      !expectedIds.every((id) => acceptedIds.includes(id)) ||
      !acceptedIds.every((id) => expectedIds.includes(id))) {
    errors.push("patch must contain exactly the three accepted safe changes");
  }
  const mirroredFields = [
    "change_id",
    "beat_id",
    "target_type",
    "target_id",
    "target_field",
    "change_type",
    "before",
    "proposed_value"
  ];
  for (const patchChange of acceptedChanges) {
    const id = String(patchChange?.change_id || "");
    const requestChange = changes.find((item) => item?.change_id === id);
    if (!requestChange) {
      errors.push(id + ": patch change is not in request");
      continue;
    }
    if (patchChange?.guard_class !== "safe_local_edit" ||
        classificationById.get(id) !== "safe_local_edit" ||
        decisionById.get(id)?.decision !== "accept") {
      errors.push(id + ": patch includes a non-safe or non-accepted change");
    }
    if (!mirroredFields.every((field) => jsonValuesEqual(patchChange?.[field], requestChange?.[field]))) {
      errors.push(id + ": patch change does not exactly mirror request");
    }
  }
  return {
    valid: errors.length === 0,
    errors,
    change_count: acceptedChanges.length
  };
}

function editorialRevisionValueHash(value) {
  const serialized = typeof value === "string" ? value : JSON.stringify(value);
  return createHash("sha256").update(Buffer.from(serialized, "utf8")).digest("hex");
}

function jsonValuesEqual(left, right) {
  return JSON.stringify(left) === JSON.stringify(right);
}

function cloneJsonValue(value) {
  return JSON.parse(JSON.stringify(value));
}

function countGuardClasses(classifications) {
  return {
    safe_local_edit: classifications.filter((item) => item.guard_class === "safe_local_edit").length,
    human_author_required: classifications.filter((item) => item.guard_class === "human_author_required").length,
    blocked_boundary: classifications.filter((item) => item.guard_class === "blocked_boundary").length
  };
}

function arraySetEquals(value, expectedSet) {
  return Array.isArray(value) &&
    value.length === expectedSet.size &&
    new Set(value).size === value.length &&
    value.every((item) => expectedSet.has(item));
}

async function readBridgeEditorialHandoffSmokeSeed(inputPath, targetPath) {
  if (await fileSizeOrZero(inputPath) > 0) {
    return readJson(inputPath);
  }
  if (path.resolve(inputPath) !== path.resolve(targetPath)) {
    return readJson(inputPath);
  }
  const handoff = await readJson(`${EDITORIAL_HANDOFF_PACKAGE_ROOT}/editorial-handoff.json`);
  return {
    schemaVersion: BRIDGE_EDITORIAL_HANDOFF_PACK_SCHEMA_VERSION,
    artifact_id: "fff-bridge-editorial-handoff-pack-001",
    editorial_status: "provisional_editorial_draft",
    review_ui: "public/review/index.html",
    review_route: "public/review/index.html?mode=handoff",
    access_route: "public/review/index.html?mode=handoff",
    bridge_route: "public/review/index.html?mode=bridge",
    brief_route: "public/review/index.html?mode=brief",
    source_storyboard_artifact_id: "fff-bridge-storyboard-flow-001",
    selected_candidate_id: handoff.selected_candidate_id,
    selected_channel_route_id: handoff.selected_channel_route_id,
    boundaries: handoff.boundaries,
    ...handoff.boundaries
  };
}

function extractFirstHtmlSectionByMarker(html, marker) {
  return extractFirstHtmlBlockByMarker(html, "section", marker);
}

function extractFirstHtmlBlockByMarker(html, tagName, marker) {
  const markerIndex = html.indexOf(marker);
  if (markerIndex < 0) {
    return "";
  }
  const start = html.lastIndexOf(`<${tagName}`, markerIndex);
  if (start < 0) {
    return "";
  }
  const tagPattern = new RegExp(`<\\/?${escapeRegExp(tagName)}\\b[^>]*>`, "gi");
  tagPattern.lastIndex = start;
  let depth = 0;
  let match;
  while ((match = tagPattern.exec(html)) !== null) {
    if (/^<\//.test(match[0])) {
      depth -= 1;
      if (depth === 0) {
        return html.slice(start, tagPattern.lastIndex);
      }
    } else {
      depth += 1;
    }
  }
  return html.slice(start);
}

function extractConstObjectBlock(text, constName) {
  const start = text.indexOf(`const ${constName} =`);
  if (start < 0) {
    return "";
  }
  const endMarker = "\n    };";
  const end = text.indexOf(endMarker, start);
  if (end < 0) {
    return text.slice(start);
  }
  return text.slice(start, end + endMarker.length);
}

function extractArrayPropertyBlock(text, propertyName) {
  const start = text.indexOf(`${propertyName}: [`);
  if (start < 0) {
    return "";
  }
  const bracketStart = text.indexOf("[", start);
  if (bracketStart < 0) {
    return "";
  }
  let depth = 0;
  for (let index = bracketStart; index < text.length; index += 1) {
    const char = text[index];
    if (char === "[") {
      depth += 1;
    } else if (char === "]") {
      depth -= 1;
      if (depth === 0) {
        return text.slice(bracketStart, index + 1);
      }
    }
  }
  return text.slice(bracketStart);
}

function removeDetailsBlocks(html) {
  return html.replace(/<details\b[\s\S]*?<\/details>/gi, "");
}

function removeHiddenBlocks(html) {
  return html.replace(/<([a-z][a-z0-9-]*)\b(?=[^>]*\bhidden\b)[\s\S]*?<\/\1>/gi, "");
}

function firstTaggedText(html, pattern) {
  const match = pattern.exec(html);
  return match ? stripHtmlTags(match[1]) : "";
}

function allTaggedTexts(html, pattern) {
  pattern.lastIndex = 0;
  const texts = [];
  let match;
  while ((match = pattern.exec(html)) !== null) {
    texts.push(stripHtmlTags(match[1]));
  }
  return texts;
}

function stripHtmlTags(html) {
  return html
    .replace(/<script\b[\s\S]*?<\/script>/gi, "")
    .replace(/<style\b[\s\S]*?<\/style>/gi, "")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeDecisionStepLabel(text) {
  return text.replace(/^[✅▶▷◇🔒\s]+/u, "").trim();
}

function countDisplayChars(text) {
  return Array.from((text || "").trim()).length;
}

function countPattern(text, pattern) {
  const matches = (text || "").match(pattern);
  return matches ? matches.length : 0;
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function countLiteral(text, literal) {
  return countPattern(text, new RegExp(escapeRegExp(literal), "g"));
}

function validateExtractionContract(contract, options = {}) {
  const label = options.label || "extraction contract";
  const errors = [];
  const warnings = [];

  if (!contract || typeof contract !== "object" || Array.isArray(contract)) {
    return { ok: false, errors: [`${label} must be an object`], warnings };
  }

  const knownContractFields = new Set(EXTRACTION_CONTRACT_REQUIRED_FIELDS);
  for (const field of Object.keys(contract)) {
    if (!knownContractFields.has(field)) {
      warnings.push(`${label} unknown top-level field ${field} will be preserved for JSON review`);
    }
  }

  for (const field of EXTRACTION_CONTRACT_REQUIRED_FIELDS) {
    if (!(field in contract)) {
      errors.push(`${label} missing ${field}`);
    }
  }

  if (contract.schemaVersion !== undefined && contract.schemaVersion !== EXTRACTION_SCHEMA_VERSION) {
    errors.push(`${label} schemaVersion must be ${EXTRACTION_SCHEMA_VERSION}`);
  }

  for (const arrayField of ["sourceRefs", "extractedElements", "profileCandidates", "claimCandidates", "timelineEntryCandidates", "unresolvedDependencies", "warnings", "humanAuthorityBoundaries"]) {
    if (arrayField in contract && !Array.isArray(contract[arrayField])) {
      errors.push(`${label} ${arrayField} must be an array`);
    }
  }

  const sourceRefIds = validateExtractionSources(contract, label, errors);
  validateReviewSafeDefaults(contract, label, errors);
  validateDecisionLogSafety(contract, label, errors);
  validateHumanAuthorityBoundaries(contract, label, errors);
  validateExtractionElements(contract, label, sourceRefIds, options, errors);
  validateExtractionClaimCandidates(contract, label, sourceRefIds, errors);

  return { ok: errors.length === 0, errors, warnings };
}

function validateExtractionSources(contract, label, errors) {
  const sourceRefIds = new Set();
  if (!Array.isArray(contract.sourceRefs)) {
    return sourceRefIds;
  }

  contract.sourceRefs.forEach((sourceRef, index) => {
    if (!sourceRef || typeof sourceRef !== "object" || Array.isArray(sourceRef)) {
      errors.push(`${label} sourceRef ${index} must be an object`);
      return;
    }
    if (!sourceRef.id || typeof sourceRef.id !== "string") {
      errors.push(`${label} sourceRef ${index} missing id`);
      return;
    }
    if (sourceRefIds.has(sourceRef.id)) {
      errors.push(`${label} duplicate sourceRef id ${sourceRef.id}`);
    }
    sourceRefIds.add(sourceRef.id);
  });

  return sourceRefIds;
}

function validateReviewSafeDefaults(contract, label, errors) {
  const defaults = contract.reviewSafeDefaults;
  if (!defaults || typeof defaults !== "object" || Array.isArray(defaults)) {
    errors.push(`${label} reviewSafeDefaults must be an object`);
    return;
  }

  for (const field of REVIEW_SAFE_DEFAULT_FIELDS) {
    if (!(field in defaults)) {
      errors.push(`${label} reviewSafeDefaults missing ${field}`);
    }
  }

  if (defaults.defaultReviewStatus === "adopt") {
    errors.push(`${label} reviewSafeDefaults.defaultReviewStatus must not be adopt`);
  }
  if (defaults.autoCanonPromotion !== false) {
    errors.push(`${label} reviewSafeDefaults.autoCanonPromotion must be false`);
  }
  if (defaults.autoChronologyPromotion !== false) {
    errors.push(`${label} reviewSafeDefaults.autoChronologyPromotion must be false`);
  }
  const unknownSourceHandling = String(defaults.unknownSourceHandling || "").toLowerCase();
  if (!unknownSourceHandling.includes("preserve") || !unknownSourceHandling.includes("hold")) {
    errors.push(`${label} reviewSafeDefaults.unknownSourceHandling must preserve unknown fields and hold candidates`);
  }
  if (defaults.defaultReviewStatus && !REVIEW_STATUSES.includes(defaults.defaultReviewStatus)) {
    errors.push(`${label} reviewSafeDefaults.defaultReviewStatus must be one of ${REVIEW_STATUSES.join(", ")}`);
  }
}

function validateDecisionLogSafety(contract, label, errors) {
  const metadata = contract.decisionLogSafeMetadata;
  if (!metadata || typeof metadata !== "object" || Array.isArray(metadata)) {
    errors.push(`${label} decisionLogSafeMetadata must be an object`);
    return;
  }

  for (const field of DECISION_LOG_SAFE_FIELDS) {
    if (!(field in metadata)) {
      errors.push(`${label} decisionLogSafeMetadata missing ${field}`);
    }
  }

  if (metadata.owner !== "human_author") {
    errors.push(`${label} decisionLogSafeMetadata.owner must be human_author`);
  }
  if (metadata.fixedPhraseRequired !== false) {
    errors.push(`${label} decisionLogSafeMetadata.fixedPhraseRequired must be false`);
  }
  if (metadata.freeformReviewAllowed !== true) {
    errors.push(`${label} decisionLogSafeMetadata.freeformReviewAllowed must be true`);
  }
  if (metadata.reversibleActionsOnly !== true) {
    errors.push(`${label} decisionLogSafeMetadata.reversibleActionsOnly must be true`);
  }
}

function validateHumanAuthorityBoundaries(contract, label, errors) {
  if (!("humanAuthorityBoundaries" in contract)) {
    return;
  }
  if (!Array.isArray(contract.humanAuthorityBoundaries) || contract.humanAuthorityBoundaries.length === 0) {
    errors.push(`${label} missing humanAuthorityBoundaries`);
    return;
  }

  const boundaryText = contract.humanAuthorityBoundaries.join(" ").toLowerCase();
  if (!boundaryText.includes("freeform") || !boundaryText.includes("source of truth")) {
    errors.push(`${label} humanAuthorityBoundaries must preserve freeform user review as source of truth`);
  }
  for (const decision of HUMAN_OWNED_DECISIONS) {
    if (!boundaryText.includes(decision.toLowerCase())) {
      errors.push(`${label} humanAuthorityBoundaries missing ${decision}`);
    }
  }
}

function validateExtractionElements(contract, label, sourceRefIds, options, errors) {
  const elements = Array.isArray(contract.extractedElements) ? contract.extractedElements : [];
  const elementTypes = new Set();
  const hasHighRisk = elements.some((element) => element?.canonRisk === "high" || touchesHumanOwnedDecision(element));

  if (hasHighRisk && (!Array.isArray(contract.warnings) || contract.warnings.length === 0)) {
    errors.push(`${label} warnings array must be present and non-empty when canon risk is high`);
  }

  elements.forEach((element, elementIndex) => {
    const elementLabel = `extraction element ${element?.id || elementIndex}`;
    if (!element || typeof element !== "object" || Array.isArray(element)) {
      errors.push(`${elementLabel} must be an object`);
      return;
    }

    for (const field of EXTRACTION_ELEMENT_REQUIRED_FIELDS) {
      if (!(field in element)) {
        errors.push(`${elementLabel} missing ${field}`);
      }
    }
    for (const arrayField of ["aliases", "sourceRefIds", "unresolvedDependencies", "targetDestinations"]) {
      if (arrayField in element && !Array.isArray(element[arrayField])) {
        errors.push(`${elementLabel} ${arrayField} must be an array`);
      }
    }
    validateElementSourceSpan(element, elementLabel, errors);

    if (element.elementType) {
      elementTypes.add(element.elementType);
      if (!REQUIRED_EXTRACTION_ELEMENT_TYPES.includes(element.elementType)) {
        errors.push(`${elementLabel} invalid elementType ${element.elementType}`);
      }
    }

    if (Array.isArray(element.sourceRefIds)) {
      if (element.sourceRefIds.length === 0) {
        errors.push(`${elementLabel} sourceRefIds must reference at least one source ref`);
      }
      for (const sourceRefId of element.sourceRefIds) {
        if (!sourceRefIds.has(sourceRefId)) {
          errors.push(`${elementLabel} sourceRefIds contains unknown source ref ${sourceRefId}`);
        }
      }
    }

    if (typeof element.confidence === "number" && (element.confidence < 0 || element.confidence > 1)) {
      errors.push(`${elementLabel} confidence must be between 0 and 1`);
    }
    if (element.suggestedReviewStatus && !REVIEW_STATUSES.includes(element.suggestedReviewStatus)) {
      errors.push(`${elementLabel} suggestedReviewStatus must be one of ${REVIEW_STATUSES.join(", ")}`);
    }

    if (Array.isArray(element.targetDestinations)) {
      if (element.targetDestinations.length === 0) {
        errors.push(`${elementLabel} targetDestinations must not be empty`);
      }
      for (const destination of element.targetDestinations) {
        if (!EXTRACTION_TARGET_DESTINATIONS.includes(destination)) {
          errors.push(`${elementLabel} invalid targetDestination ${destination}`);
        }
      }
      if (element.elementType === "visual_asset" && element.targetDestinations.includes("claim") && !element.targetDestinations.includes("profile")) {
        errors.push(`${elementLabel} visual_asset must not route directly to Claim Ledger`);
      }
    }

    if (touchesHumanOwnedDecision(element) && element.suggestedReviewStatus === "adopt") {
      errors.push(`${elementLabel} touches a human-owned decision and must not suggest adopt`);
    }
    if (touchesHumanOwnedDecision(element) && typeof element.confidence === "number" && element.confidence >= 0.9 && element.suggestedReviewStatus !== "hold") {
      errors.push(`${elementLabel} is overconfident on a human-owned decision; suggestedReviewStatus must remain hold`);
    }
  });

  if (options.requireCompleteElementTypeCoverage) {
    for (const elementType of REQUIRED_EXTRACTION_ELEMENT_TYPES) {
      if (!elementTypes.has(elementType)) {
        errors.push(`${label} missing elementType ${elementType}`);
      }
    }
  }
}

function validateElementSourceSpan(element, elementLabel, errors) {
  const sourceSpan = element.sourceSpan;
  if (!sourceSpan || typeof sourceSpan !== "object" || Array.isArray(sourceSpan)) {
    errors.push(`${elementLabel} sourceSpan must be an object`);
    return;
  }

  if (typeof sourceSpan.text !== "string" || sourceSpan.text.trim().length === 0) {
    errors.push(`${elementLabel} sourceSpan.text must be a non-empty string`);
  }
  if (!Number.isInteger(sourceSpan.start) || sourceSpan.start < 0) {
    errors.push(`${elementLabel} sourceSpan.start must be a non-negative integer`);
  }
  if (!Number.isInteger(sourceSpan.end) || sourceSpan.end < 0) {
    errors.push(`${elementLabel} sourceSpan.end must be a non-negative integer`);
  }
  if (Number.isInteger(sourceSpan.start) && Number.isInteger(sourceSpan.end) && sourceSpan.end <= sourceSpan.start) {
    errors.push(`${elementLabel} sourceSpan.end must be greater than sourceSpan.start`);
  }
}

function touchesHumanOwnedDecision(element) {
  if (!element || typeof element !== "object") {
    return false;
  }
  if (element.elementType === "unresolved_decision") {
    return true;
  }
  const dependencies = Array.isArray(element.unresolvedDependencies) ? element.unresolvedDependencies : [];
  const searchable = [
    element.displayText,
    element.notes,
    ...dependencies
  ].filter(Boolean).join(" ").toLowerCase();
  return HUMAN_OWNED_DECISIONS.some((decision) => searchable.includes(decision.toLowerCase()));
}

function validateExtractionClaimCandidates(contract, label, sourceRefIds, errors) {
  const claims = Array.isArray(contract.claimCandidates) ? contract.claimCandidates : [];
  const claimById = new Map();

  claims.forEach((claim, index) => {
    const claimLabel = `claim candidate ${claim?.id || index}`;
    if (!claim || typeof claim !== "object" || Array.isArray(claim)) {
      errors.push(`${claimLabel} must be an object`);
      return;
    }
    if (!claim.id || typeof claim.id !== "string") {
      errors.push(`${claimLabel} missing id`);
      return;
    }
    if (claimById.has(claim.id)) {
      errors.push(`${label} duplicate claim candidate id ${claim.id}`);
    }
    claimById.set(claim.id, claim);
  });

  claims.forEach((claim, index) => {
    const claimLabel = `claim candidate ${claim?.id || index}`;
    if (!claim || typeof claim !== "object" || Array.isArray(claim)) {
      return;
    }

    for (const arrayField of ["sourceRefs", "subjectRefs", "unresolvedDependencies", "supportsClaimIds", "contradictsClaimIds"]) {
      if (arrayField in claim && !Array.isArray(claim[arrayField])) {
        errors.push(`${claimLabel} ${arrayField} must be an array`);
      }
    }
    if (claim.reviewStatus && !REVIEW_STATUSES.includes(claim.reviewStatus)) {
      errors.push(`${claimLabel} reviewStatus must be one of ${REVIEW_STATUSES.join(", ")}`);
    }

    if (Array.isArray(claim.sourceRefs)) {
      if (claim.sourceRefs.length === 0) {
        errors.push(`${claimLabel} sourceRefs must preserve at least one source ref`);
      }
      for (const sourceRef of claim.sourceRefs) {
        const sourceRefId = typeof sourceRef === "string" ? sourceRef : sourceRef?.id;
        if (!sourceRefId || typeof sourceRefId !== "string") {
          errors.push(`${claimLabel} sourceRefs must include ids or source ref objects with id`);
        }
      }
    }

    const contradicts = Array.isArray(claim.contradictsClaimIds) ? claim.contradictsClaimIds : [];
    if (contradicts.length === 0) {
      return;
    }

    if (claim.reviewStatus !== "hold") {
      errors.push(`${claimLabel} contradictory claim candidate must remain hold for human review`);
    }

    for (const contradictedId of contradicts) {
      const target = claimById.get(contradictedId);
      if (!target) {
        errors.push(`${claimLabel} contradicts unknown claim candidate ${contradictedId}`);
        continue;
      }
      const reciprocal = Array.isArray(target.contradictsClaimIds) && target.contradictsClaimIds.includes(claim.id);
      if (!reciprocal) {
        errors.push(`${claimLabel} contradictory claim link to ${contradictedId} must be reciprocal`);
      }
    }
  });
}

function validateState(state) {
  const errors = [];
  if (!state || typeof state !== "object" || Array.isArray(state)) {
    return { ok: false, errors: ["state must be an object"] };
  }

  if (state.schemaVersion !== SCHEMA_VERSION) {
    errors.push(`schemaVersion must be ${SCHEMA_VERSION}`);
  }

  for (const field of REQUIRED_FIELDS) {
    if (!(field in state)) {
      errors.push(`missing ${field}`);
    }
  }

  if (typeof state.rawMemo !== "string") {
    errors.push("rawMemo must be a string");
  }

  for (const arrayField of ["unresolvedCreativeDecisions", "taskCards", "qaGateResults", "generatedOutlines", "decisionLog"]) {
    if (!Array.isArray(state[arrayField])) {
      errors.push(`${arrayField} must be an array`);
    }
  }

  if (!state.extractedCandidates || typeof state.extractedCandidates !== "object" || Array.isArray(state.extractedCandidates)) {
    errors.push("extractedCandidates must be an object");
  }

  if (!state.reviewStatuses || typeof state.reviewStatuses !== "object" || Array.isArray(state.reviewStatuses)) {
    errors.push("reviewStatuses must be an object");
  }

  const profiles = state.extractedCandidates?.profiles;
  if (profiles !== undefined) {
    if (!Array.isArray(profiles)) {
      errors.push("extractedCandidates.profiles must be an array");
    } else {
      const profileTypes = new Set();
      const ghostStatuses = new Set();
      profiles.forEach((profile, index) => {
        if (!profile || typeof profile !== "object" || Array.isArray(profile)) {
          errors.push(`profile ${index} must be an object`);
          return;
        }
        for (const field of PROFILE_REQUIRED_FIELDS) {
          if (!(field in profile)) {
            errors.push(`profile ${profile.id || index} missing ${field}`);
          }
        }
        for (const arrayField of ["aliases", "linkedClaimIds", "linkedTimelineEntryIds", "relatedProfileIds", "unresolvedDependencies", "knownBy", "unknownBy", "believedBy", "misunderstoodBy", "ownedItems", "sourceRefs", "assetRefs"]) {
          if (arrayField in profile && !Array.isArray(profile[arrayField])) {
            errors.push(`profile ${profile.id || index} ${arrayField} must be an array`);
          }
        }
        if (profile.profileType) {
          profileTypes.add(profile.profileType);
        }
        if (profile.ghostNodeStatus) {
          ghostStatuses.add(profile.ghostNodeStatus);
        }
      });

      for (const profileType of REQUIRED_PROFILE_TYPES) {
        if (!profileTypes.has(profileType)) {
          errors.push(`profiles missing required profileType ${profileType}`);
        }
      }
      for (const ghostStatus of REQUIRED_GHOST_NODE_STATUSES) {
        if (!ghostStatuses.has(ghostStatus)) {
          errors.push(`profiles missing required ghostNodeStatus ${ghostStatus}`);
        }
      }
    }
  }

  const claims = state.extractedCandidates?.claims;
  if (claims !== undefined) {
    if (!Array.isArray(claims)) {
      errors.push("extractedCandidates.claims must be an array");
    } else {
      claims.forEach((claim, index) => {
        if (!claim || typeof claim !== "object" || Array.isArray(claim)) {
          errors.push(`claim ${index} must be an object`);
          return;
        }
        for (const field of CLAIM_REQUIRED_FIELDS) {
          if (!(field in claim)) {
            errors.push(`claim ${claim.id || index} missing ${field}`);
          }
        }
        for (const arrayField of ["sourceRefs", "subjectRefs", "unresolvedDependencies", "supportsClaimIds", "contradictsClaimIds"]) {
          if (arrayField in claim && !Array.isArray(claim[arrayField])) {
            errors.push(`claim ${claim.id || index} ${arrayField} must be an array`);
          }
        }
      });
    }
  }

  const timelineEntries = state.extractedCandidates?.timelineCandidates;
  if (timelineEntries !== undefined) {
    if (!Array.isArray(timelineEntries)) {
      errors.push("extractedCandidates.timelineCandidates must be an array");
    } else {
      timelineEntries.forEach((entry, index) => {
        if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
          errors.push(`timeline entry ${index} must be an object`);
          return;
        }
        for (const field of TIMELINE_REQUIRED_FIELDS) {
          if (!(field in entry)) {
            errors.push(`timeline entry ${entry.id || index} missing ${field}`);
          }
        }
        for (const arrayField of ["linkedClaimIds", "linkedProfileIds", "linkedWorkIds", "unresolvedDependencies", "sourceRefs"]) {
          if (arrayField in entry && !Array.isArray(entry[arrayField])) {
            errors.push(`timeline entry ${entry.id || index} ${arrayField} must be an array`);
          }
        }
      });
    }
  }

  const extractionContracts = Array.isArray(state.extractionContracts) ? state.extractionContracts : state.extractionContract ? [state.extractionContract] : [];
  extractionContracts.forEach((contract, contractIndex) => {
    const validation = validateExtractionContract(contract, {
      label: `extraction contract ${contract?.extractionRunId || contractIndex}`,
      requireCompleteElementTypeCoverage: true
    });
    errors.push(...validation.errors);
  });

  return { ok: errors.length === 0, errors };
}

function normalizeState(state) {
  return {
    ...state,
    schemaVersion: SCHEMA_VERSION,
    exportedAt: new Date().toISOString(),
    metadata: {
      ...(state.metadata && typeof state.metadata === "object" ? state.metadata : {}),
      normalizedBy: "tools/fff-state.mjs"
    }
  };
}

function summarizeState(state) {
  return {
    schemaVersion: state.schemaVersion,
    projectTitle: state.project?.title || null,
    workTitle: state.work?.title || null,
    memoCharacters: state.rawMemo.length,
    reviewStatusCounts: countStatuses(state.reviewStatuses),
    extractedCategories: Array.isArray(state.extractedCandidates?.elements) ? state.extractedCandidates.elements.length : 0,
    profiles: Array.isArray(state.extractedCandidates?.profiles) ? state.extractedCandidates.profiles.length : 0,
    profileSummary: summarizeProfiles(state),
    claims: Array.isArray(state.extractedCandidates?.claims) ? state.extractedCandidates.claims.length : 0,
    claimSummary: summarizeClaims(state),
    timelineCandidates: Array.isArray(state.extractedCandidates?.timelineCandidates) ? state.extractedCandidates.timelineCandidates.length : 0,
    timelineSummary: summarizeTimeline(state),
    extractionContractSummary: summarizeExtractionContracts(state),
    unresolvedCreativeDecisions: state.unresolvedCreativeDecisions.length,
    taskCards: state.taskCards.length,
    qaGateResults: state.qaGateResults.length,
    generatedOutlines: state.generatedOutlines.length,
    decisionLogEntries: state.decisionLog.length
  };
}

function summarizeExtractionContracts(state) {
  const contracts = Array.isArray(state.extractionContracts) ? state.extractionContracts : state.extractionContract ? [state.extractionContract] : [];
  return summarizeExtractionContractList(contracts);
}

function summarizeExtractionContractList(contracts) {
  const byElementType = {};
  let extractedElementCount = 0;
  let profileCandidateCount = 0;
  let claimCandidateCount = 0;
  let timelineCandidateCount = 0;
  let unresolvedDependencyCount = 0;
  let highCanonRiskCount = 0;
  let warningsCount = 0;

  for (const contract of contracts) {
    const elements = Array.isArray(contract.extractedElements) ? contract.extractedElements : [];
    extractedElementCount += elements.length;
    profileCandidateCount += Array.isArray(contract.profileCandidates) ? contract.profileCandidates.length : 0;
    claimCandidateCount += Array.isArray(contract.claimCandidates) ? contract.claimCandidates.length : 0;
    timelineCandidateCount += Array.isArray(contract.timelineEntryCandidates) ? contract.timelineEntryCandidates.length : 0;
    unresolvedDependencyCount += Array.isArray(contract.unresolvedDependencies) ? contract.unresolvedDependencies.length : 0;
    warningsCount += Array.isArray(contract.warnings) ? contract.warnings.length : 0;

    for (const element of elements) {
      const elementType = element.elementType || "not set";
      byElementType[elementType] = (byElementType[elementType] || 0) + 1;
      if (element.canonRisk === "high") {
        highCanonRiskCount += 1;
      }
    }
  }

  return {
    extractionRunCount: contracts.length,
    extractedElementCount,
    byElementType,
    profileCandidateCount,
    claimCandidateCount,
    timelineCandidateCount,
    unresolvedDependencyCount,
    highCanonRiskCount,
    warningsCount
  };
}

function summarizeProfiles(state) {
  const profiles = Array.isArray(state.extractedCandidates?.profiles) ? state.extractedCandidates.profiles : [];
  const byProfileType = {};
  const byGhostNodeStatus = {};
  const byReviewStatus = { adopt: 0, provisional: 0, hold: 0, reject: 0, other: 0 };
  let withUnresolvedDependencies = 0;
  let highCanonRisk = 0;
  let spoilerProtected = 0;
  let linkedToClaims = 0;
  let linkedToTimeline = 0;
  let placeholderProfiles = 0;

  for (const profile of profiles) {
    const profileType = profile.profileType || profile.profile_type || "not set";
    const ghostNodeStatus = profile.ghostNodeStatus || profile.ghost_node_status || "not set";
    byProfileType[profileType] = (byProfileType[profileType] || 0) + 1;
    byGhostNodeStatus[ghostNodeStatus] = (byGhostNodeStatus[ghostNodeStatus] || 0) + 1;

    const status = state.reviewStatuses?.[profile.id] || profile.reviewStatus || profile.review_status || "hold";
    if (status in byReviewStatus) {
      byReviewStatus[status] += 1;
    } else {
      byReviewStatus.other += 1;
    }
    if (Array.isArray(profile.unresolvedDependencies) && profile.unresolvedDependencies.length > 0) {
      withUnresolvedDependencies += 1;
    }
    if (profile.canonRisk === "high") {
      highCanonRisk += 1;
    }
    if (profile.spoilerLevel === "high") {
      spoilerProtected += 1;
    }
    if (Array.isArray(profile.linkedClaimIds) && profile.linkedClaimIds.length > 0) {
      linkedToClaims += 1;
    }
    if (Array.isArray(profile.linkedTimelineEntryIds) && profile.linkedTimelineEntryIds.length > 0) {
      linkedToTimeline += 1;
    }
    if (profileType === "placeholder") {
      placeholderProfiles += 1;
    }
  }

  return {
    totalProfiles: profiles.length,
    byProfileType,
    byGhostNodeStatus,
    byReviewStatus,
    withUnresolvedDependencies,
    highCanonRisk,
    spoilerProtected,
    linkedToClaims,
    linkedToTimeline,
    placeholderProfiles
  };
}

function summarizeTimeline(state) {
  const entries = Array.isArray(state.extractedCandidates?.timelineCandidates) ? state.extractedCandidates.timelineCandidates : [];
  const byTimelineAxis = {};
  const byReviewStatus = { adopt: 0, provisional: 0, hold: 0, reject: 0, other: 0 };
  let withUnresolvedDependencies = 0;
  let hiddenOrSpoilerProtected = 0;
  let highCanonRisk = 0;
  let linkedToClaims = 0;

  for (const entry of entries) {
    const axis = entry.timelineAxis || entry.sequence_scope || "not set";
    byTimelineAxis[axis] = (byTimelineAxis[axis] || 0) + 1;
    const status = state.reviewStatuses?.[entry.id] || entry.reviewStatus || entry.review_status || "hold";
    if (status in byReviewStatus) {
      byReviewStatus[status] += 1;
    } else {
      byReviewStatus.other += 1;
    }
    if (Array.isArray(entry.unresolvedDependencies) && entry.unresolvedDependencies.length > 0) {
      withUnresolvedDependencies += 1;
    }
    if (entry.spoilerLevel === "high" || String(entry.viewerDisclosureStatus || "").includes("hidden") || String(entry.viewerDisclosureStatus || "").includes("not yet")) {
      hiddenOrSpoilerProtected += 1;
    }
    if (entry.canonRisk === "high") {
      highCanonRisk += 1;
    }
    if (Array.isArray(entry.linkedClaimIds) && entry.linkedClaimIds.length > 0) {
      linkedToClaims += 1;
    }
  }

  return {
    totalTimelineEntries: entries.length,
    byTimelineAxis,
    byReviewStatus,
    withUnresolvedDependencies,
    hiddenOrSpoilerProtected,
    highCanonRisk,
    linkedToClaims
  };
}

function summarizeClaims(state) {
  const claims = Array.isArray(state.extractedCandidates?.claims) ? state.extractedCandidates.claims : [];
  const byReviewStatus = { adopt: 0, provisional: 0, hold: 0, reject: 0, other: 0 };
  let withUnresolvedDependencies = 0;
  let highCanonRisk = 0;
  let unverifiedRealityStatus = 0;
  let hiddenOrSpoilerProtected = 0;

  for (const claim of claims) {
    const status = state.reviewStatuses?.[claim.id] || claim.reviewStatus || claim.review_status || "hold";
    if (status in byReviewStatus) {
      byReviewStatus[status] += 1;
    } else {
      byReviewStatus.other += 1;
    }
    if (Array.isArray(claim.unresolvedDependencies) && claim.unresolvedDependencies.length > 0) {
      withUnresolvedDependencies += 1;
    }
    if (claim.canonRisk === "high") {
      highCanonRisk += 1;
    }
    if (claim.realityStatus === "unverified") {
      unverifiedRealityStatus += 1;
    }
    if (claim.spoilerLevel === "high" || String(claim.viewerDisclosureStatus || "").includes("hidden") || String(claim.viewerDisclosureStatus || "").includes("not yet")) {
      hiddenOrSpoilerProtected += 1;
    }
  }

  return {
    totalClaims: claims.length,
    byReviewStatus,
    withUnresolvedDependencies,
    highCanonRisk,
    unverifiedRealityStatus,
    hiddenOrSpoilerProtected
  };
}

function countStatuses(reviewStatuses) {
  const counts = { adopt: 0, provisional: 0, hold: 0, reject: 0, other: 0 };
  for (const status of Object.values(reviewStatuses || {})) {
    if (status in counts) {
      counts[status] += 1;
    } else {
      counts.other += 1;
    }
  }
  return counts;
}

