function beat2CompositionClone(value) {
  return JSON.parse(JSON.stringify(value));
}

function beat2CompositionHash(buffer) {
  return createHash("sha256").update(buffer).digest("hex");
}

function beat2CompositionJpegDimensions(buffer) {
  if (!buffer || buffer[0] !== 0xff || buffer[1] !== 0xd8) return null;
  let offset = 2;
  while (offset + 9 < buffer.length) {
    if (buffer[offset] !== 0xff) { offset += 1; continue; }
    const marker = buffer[offset + 1];
    if ([0xc0, 0xc1, 0xc2, 0xc3, 0xc5, 0xc6, 0xc7, 0xc9, 0xca, 0xcb, 0xcd, 0xce, 0xcf].includes(marker)) {
      return { height: buffer.readUInt16BE(offset + 5), width: buffer.readUInt16BE(offset + 7) };
    }
    if (marker === 0xd8 || marker === 0xd9) { offset += 2; continue; }
    const length = buffer.readUInt16BE(offset + 2);
    if (!length) break;
    offset += length + 2;
  }
  return null;
}

function beat2CompositionPngDimensions(buffer) {
  if (!buffer || buffer.length < 24 || buffer.toString("ascii", 1, 4) !== "PNG") return null;
  return { width: buffer.readUInt32BE(16), height: buffer.readUInt32BE(20) };
}

async function beat2CompositionAggregate(root, files) {
  const rows = [];
  for (const name of files) {
    const snapshot = await readFileSnapshot(path.join(root, name));
    rows.push(`${root}/${name}|${snapshot.byteSize}|${snapshot.sha256}`);
  }
  return beat2CompositionHash(Buffer.from(rows.sort().join("\n"), "utf8"));
}

async function beat2CompositionSourceSnapshot() {
  const pilotManifest = await readJsonFileSnapshot("artifacts/beat2-visual-treatment-pilot/beat2-visual-treatment-manifest.json");
  return {
    visual_treatment_manifest_sha256: pilotManifest.sha256,
    visual_treatment_package_fingerprint_sha256: pilotManifest.value?.package_fingerprint_sha256 || null,
    visual_treatment_thirteen_file_aggregate_sha256: await beat2CompositionAggregate("artifacts/beat2-visual-treatment-pilot", BEAT2_COMPOSITION_SOURCE_FILES["artifacts/beat2-visual-treatment-pilot"]),
    storyboard_seven_file_aggregate_sha256: await beat2CompositionAggregate("artifacts/production-storyboard-brief", BEAT2_COMPOSITION_SOURCE_FILES["artifacts/production-storyboard-brief"]),
    execution_nine_file_aggregate_sha256: await beat2CompositionAggregate("artifacts/production-execution-pack", BEAT2_COMPOSITION_SOURCE_FILES["artifacts/production-execution-pack"])
  };
}

function beat2CompositionSourceErrors(observed) {
  const failures = [];
  for (const [key, expected] of Object.entries(BEAT2_COMPOSITION_SOURCE_FINGERPRINTS)) {
    if (observed?.[key] !== expected) failures.push(`protected source mismatch: ${key}`);
  }
  return failures;
}

async function runPreservedBeat4CompositionCounterexampleValidation({ inputPath, outputPath }) {
  const target = toRepoPath(inputPath || "artifacts/beat4-composition-counterexample-result.json");
  if (target !== "artifacts/beat4-composition-counterexample-result.json") fail("Preserved Beat 4 Counterexample validation requires artifacts/beat4-composition-counterexample-result.json.");
  if (outputPath) fail("Preserved Beat 4 Counterexample validation does not accept an output path.");
  const [root, recorded, manifest, reviewDoc] = await Promise.all([
    readJsonFileSnapshot("artifacts/artifact-manifest.json"),
    readJsonFileSnapshot(target),
    readJsonFileSnapshot("artifacts/beat4-composition-counterexample/manifest.json"),
    readFileSnapshot("docs/review/beat4-composition-counterexample.md")
  ]);
  const failures = [];
  const entry = root.value?.beat4_composition_counterexample || {};
  if (!["fff-composition-expansion-wave1-001", "fff-composition-expansion-wave2-001", "fff-integrated-visual-production-package-001"].includes(root.value?.artifact_id) || !root.value?.preserves?.includes("fff-beat4-composition-counterexample-001")) failures.push("preserved Beat 4 is not registered beneath an active composition expansion wave");
  if (entry.artifact_id !== "fff-beat4-composition-counterexample-001" || entry.package_root !== "artifacts/beat4-composition-counterexample" || entry.result_path !== target || entry.review_doc_path !== "docs/review/beat4-composition-counterexample.md") failures.push("preserved Beat 4 nested registration mismatch");
  if (!recorded.exists || recorded.sha256 !== "437c342b03aa5b81ad09f2e0f1965e77d92db721ee3ed4a01007ad4664f39db9" || recorded.value?.artifact_id !== "fff-beat4-composition-counterexample-001" || recorded.value?.passed !== true || !Array.isArray(recorded.value?.negative_probes) || recorded.value.negative_probes.length !== 30 || recorded.value.negative_probes.some((probe) => probe.passed !== true || probe.mutation !== false)) failures.push("preserved Beat 4 recorded H0 result mismatch");
  if (!manifest.exists || manifest.sha256 !== "28be65595282dde9a79f72535ce589b6eec6ab6c25087d85e4e2859550f77943" || manifest.value?.artifact_id !== "fff-beat4-composition-counterexample-001" || manifest.value?.file_count !== 14 || manifest.value?.payload_file_count !== 13) failures.push("preserved Beat 4 manifest mismatch");
  for (const item of manifest.value?.files || []) {
    const snapshot = await readFileSnapshot(`artifacts/beat4-composition-counterexample/${item.path}`);
    if (!snapshot.exists || snapshot.byteSize !== item.byte_size || snapshot.sha256 !== item.sha256) failures.push(`preserved Beat 4 package file mismatch: ${item.path}`);
  }
  if (!reviewDoc.exists || reviewDoc.sha256 !== "3a5c0df670599db74f55e5612fa2bfb7b88098ae833d614aa97fcbfb91db39f9") failures.push("preserved Beat 4 review evidence mismatch");
  const command = String(root.value?.validation_command || "");
  const indexes = [
    "validate-composition-expansion-wave1 artifacts/composition-expansion-wave1-result.json",
    `validate-beat2-composition-board ${DEFAULT_BEAT2_COMPOSITION_BOARD_OUTPUT}`,
    "validate-beat4-composition-counterexample artifacts/beat4-composition-counterexample-result.json"
  ].map((needle) => command.indexOf(needle));
  if (indexes.some((value) => value < 0) || indexes.some((value, index) => index > 0 && value <= indexes[index - 1]) || command.includes("smoke-beat4-composition-counterexample")) failures.push("preserved Beat 4 read-only validation chain mismatch");
  if (failures.length) fail(`Beat 4 Counterexample preserved read-only validation failed: ${[...new Set(failures)].join("; ")}`);
  console.log(`Beat 4 Counterexample preserved read-only validation passed: ${target}`);
}

